namespace IstanbulAnkaraNakliyat.Models;

public static class AnkaraIlceDetaylar
{
    public static string GetIlceDetay(string slug) =>
        IlceDetaylar.TryGetValue(slug, out var d) ? d : "";

    public static string GetServisDetay(string slug, ServisTipi servis) =>
        ServisDetaylar.TryGetValue((slug, servis), out var d) ? d : "";

    private static readonly Dictionary<string, string> IlceDetaylar = new()
    {
        ["cankaya"] = "Çankaya, Ankara'nın merkezi idari ve ticari kalbi olup Kızılay, Balgat, Oran ve Kavaklidere gibi farklı yaşam dokularını barındırır. Diplomatik konutların yoğun olduğu Oran ve GOP bölgelerinde büyük sitelerin servis girişleri ve asansör planlaması önceden sorgulanmaktadır. Çukurambar ve Kavaklidere'nin iş merkezi akslarında sabah 08:00–09:30 arası trafik yoğunluğu nedeniyle yükleme saatinin buna göre ayarlanması önerilir.",
        ["kecioren"] = "Keçiören, Ankara'nın en kalabalık ilçesi olup Etlik, Bağlum ve Kalaba mahallelerinde binlerce konut bloğunu barındırır. İlçedeki dar ara sokaklar zaman zaman büyük araç erişimini güçleştirse de 3,5 tonluk kamyonetimiz bu bölgeler için standart çözüm sunmaktadır. Özellikle Keçiören TOKİ bloklarında asansör kullanımı önceden koordine edilerek yükleme planı oluşturulmaktadır.",
        ["yenimahalle"] = "Yenimahalle, TEM E-80 otoyoluna en hızlı bağlantıyı sunan Ankara ilçelerinden biridir; bu coğrafi konum İstanbul taşımalarında seyir başlangıcını minimize eder. Batıkent ve Demetevler'in planlı kentsel düzeni geniş yollar ve otopark alanları sağlamakta, büyük kamyonların dahi kolayca manevra yapabilmesine imkân tanımaktadır. Ostim OSB'nin yakınlığı, bu bölgeden kurumsal ofis ve ekipman taşımalarını düzenli hale getirmiştir.",
        ["mamak"] = "Mamak, Ankara'nın doğu yakasında eğimli arazisi ve kökleşmiş semtleriyle kendine özgü bir lojistik yapısına sahiptir. Tuzluçayır ve Hüseyingazi gibi kalabalık semtlerde yüksek katlı konutlar çoğunlukla asansörlüdür; kat başına taşıma süresi hesaba katılarak güne erken başlanması önerilir. Mamak Merkez ve Kutlu mahallelerinin bir kısmında yol genişliğindeki kısıtlamalar kamyonet ile çözülmektedir.",
        ["etimesgut"] = "Etimesgut, Ankara'nın en hızlı büyüyen konut ilçelerinden biri olup Eryaman'daki TOKİ projeleri ile Elvankent sitelerinde on binlerce aile yaşamaktadır. Geniş anayollar ve organize yapı, büyük tonajlı kamyonların dahi sorunsuz çalışmasına imkân tanır; 3+1 ve üzeri daire taşımaları bu nedenle Etimesgut'ta sık gerçekleştirilmektedir. Batı Çevre Yolu'na yakın konumuyla İstanbul güzergâhına hızlı bağlantı sağlanmaktadır.",
        ["sincan"] = "Sincan, TEM E-80 otoyolunun Ankara'ya giriş noktasına fiilen en yakın ilçe olup şehirlerarası taşımalarda güzergâh avantajı sağlamaktadır. OSB'nin ağır araç altyapısına alışkın ortamı, büyük kamyon ve tır hareket planlamasını kolaylaştırmaktadır. Sincan–Fatih ve Pirinçlik mahallelerindeki yeni konut projelerinde asansörlü yapı oranı giderek artmaktadır.",
        ["altindag"] = "Altındağ, Ankara'nın tarihi çekirdeği olup Ulus, Hamamönü ve Anafartalar ticaret bölgeleri dar sokak dokusuyla bilinmektedir. Bu bölgelerde büyük kamyon erişimi güç olduğundan 3,5 tonluk kamyonet standart çözümdür; yükleme saatlerinde ticari araç kısıtlamalarına dikkat edilmektedir. Çiçek ve Atıfbey gibi yüksek katlı konut alanlarında ise asansör planlamasıyla verimli yükleme sağlanmaktadır.",
        ["golbasi"] = "Gölbaşı, Mogan ve Eymir gölleri çevresindeki villa ve müstakil konut yoğunluğuyla Ankara'nın yeşil ilçesi konumundadır. Bu yapı nedeniyle büyük eşya hacimleri ve değerli mobilya taşımaları burada sık karşılaşılan bir hizmet talebidir. Ankara–Konya yolundan Çevre Yolu'na bağlanarak TEM'e erişim sağlanmakta; sabah trafiği öncesinde çıkış önerilmektedir.",
        ["pursaklar"] = "Pursaklar, kuzey Ankara'nın gelecek vaat eden gelişim ilçesidir; İstasyon ve Saray mahallelerindeki yeni konut sitelerinde yüksek taşınma talebi yaşanmaktadır. Keçiören–Pursaklar bağlantı yolunun nispeten az trafikli olması, sabah saatlerinde hızlı çıkış imkânı sunmaktadır. Yeni yapı stoku nedeniyle asansörlü binalardaki taşımalarda planlı koordinasyon standart hâle gelmiştir.",
        ["polatli"] = "Polatlı, Ankara'nın batısında Ege ve İç Anadolu'ya açılan kapı konumundadır; ancak İstanbul güzergâhı için araçlar kuzey Ankara çevre yolundan TEM'e bağlanmaktadır. Bu ek güzergâh, Polatlı'dan İstanbul'a olan fiilî mesafeyi yaklaşık 500 km'nin üzerine çıkarmaktadır. Özellikle parsiyel ve kamyonet hizmetlerinde bu mesafe farkı fiyata yansıyabilir; keşif aşamasında net bilgi verilmektedir.",
        ["akyurt"] = "Akyurt, kuzeydoğu Ankara'da büyüyen sanayi ve konut ilçesidir; Karaağaç ve Yaylabağ gibi semt merkezleri sanayi alanlarına yakın konumdadır. Bazı köy ve bağ yollarında araç genişliği kısıtlaması bulunduğundan büyük kamyon kullanımı önceden değerlendirilmektedir. İlçe merkezine erişen ana yollar yeterli genişlikte olup sanayi taşımacılığına alışkın yapıdadır.",
        ["elmadag"] = "Elmadağ, Ankara'nın doğusunda ormanlık ve askeri alan yoğunluklu bir ilçe olup bazı güzergahlar kısıtlı erişim bariyeri içermektedir. Elmadağ Merkez ve Hasanoğlan mahallelerinin sivil konut bölgelerine kamyonet erişimi sorunsuz sağlanmaktadır. İstanbul güzergâhı için Mamak–Çankaya aksından Çevre Yolu'na bağlanılmakta olup kış aylarında dağ geçit noktaları takip edilmektedir.",
        ["beypazari"] = "Beypazarı, Osmanlı döneminden kalma tarihi konak dokusuyla Ankara'nın kültürel ilçesidir ve merkeze yaklaşık 100 km uzaklığıyla özel rota planlaması gerektirmektedir. Doğrudan Bolu otoyol güzergâhının yakınlığı, bazı durumlarda İstanbul'a daha kısa güzergâh imkânı sunabilmektedir. Tarihi yapılar nedeniyle dar sokaklar yaygındır; ağır araç girişi öncesinde adres bazlı değerlendirme yapılmaktadır.",
        ["kahramankazan"] = "Kahramankazan, OSB ve Organize Sanayi Bölgesi altyapısıyla büyük tonajlı araçlara alışkın lojistik yapısıyla öne çıkan bir ilçedir. TEM'e Sincan üzerinden doğrudan erişim, İstanbul taşımacılığında mesafe avantajı sağlamaktadır. Konut mahallelerinde de modern yapı stoku artmakta olup asansörlü binalardaki taşımalar için kapasite planlaması yapılmaktadır.",
        ["cubuk"] = "Çubuk, Ankara'ya yaklaşık 45 km uzaklıkta bağlı bir ilçe olup bazı semtleri ara yollarla bağlantılıdır. İlçe merkezi ve Ovacık gibi yakın mahallelere 3,5 ton kamyonetimiz kolayca ulaşmaktadır; şehirlerarası araç ise Çubuk çıkışında bekleyerek ikincil transferle koordineli çalışır. Kış aylarında bazı köy yollarında hava koşullarının takip edilmesi önerilmektedir.",
        ["kizilcahamam"] = "Kızılcahamam, Ankara'ya yaklaşık 80 km mesafedeki termal turizm ve ormanlık ilçesidir. İstanbul güzergâhı için Bolu üzerinden TEM'e bağlanan alternatif rota Ankara şehir merkezini tamamen bypass etmekte ve zaman kazandırmaktadır. İlçede apart otel ve termal tesis taşımaları da gerçekleştirildiğinden ticari nakliyat deneyimine sahibiz.",
        ["nallihan"] = "Nallıhan, Ankara'nın en batı ilçesi olup Bolu–TEM güzergâhına coğrafi olarak diğer Ankara ilçelerinden çok daha yakın konumdadır. Bu stratejik konum, İstanbul taşımalarında toplam yol mesafesini Ankara merkeze kıyasla azaltabilmektedir. İlçe merkezinden çıkış için Çayırhan güzergâhının trafiği sabah erken saatte oldukça serbest seyreder.",
        ["ayas"] = "Ayaş, bağları ve yayla havası ile Ankara'ya yaklaşık 60 km mesafedeki sakin bir ilçedir. İstanbul güzergâhı için araçlar Sincan veya Nallıhan üzerinden TEM'e ulaşmaktadır; bu bağlantı güzergâhında trafik yoğunluğu Ankara merkezine kıyasla oldukça az olmaktadır. Yükleme erken sabah başlatıldığında İstanbul'a aynı günde teslimat sağlanmaktadır.",
        ["bala"] = "Bala, Ankara'nın güneydoğusunda Kızılırmak havzasındaki tarım ilçesidir ve Ankara merkezine yaklaşık 80 km uzaklığıyla birleşik güzergâh planlaması gerekmektedir. Ankara Çevre Yolu'na çıkış için Çankaya aksından geçilmekte, ardından TEM'e bağlanılmaktadır. Bu kademeli güzergâh nedeniyle erken saatte başlayan yüklemeler tercih edilmektedir.",
        ["gudul"] = "Güdül, Ankara Boğazı kanyonu ve Bozan çevresindeki ormanlık arazi nedeniyle ulaşım için özellikli rota planlaması gerektiren bir ilçedir. İlçe merkezine giden yolun büyük bölümü çift yönlü trafiğe uygun olmakla birlikte bazı köy yolları dar ya da eğimlidir. Yükleme öncesinde adresin büyük araç erişimine uygunluğu mutlaka kontrol edilmektedir.",
        ["camlidere"] = "Çamlıdere, Kuzey Ankara Ormanı içinde gizlenmiş ve sınırlı karayolu bağlantılarıyla erişilen bir ilçedir. İstanbul güzergâhı için Kızılcahamam–Bolu yolu kullanılmakta olup bu rota Ankara şehir merkezini atlayarak zaman tasarrufu sağlayabilmektedir. İlçe sınırlarındaki bazı köy yollarına yalnızca kamyonet ölçeğinde araç girişi mümkündür.",
        ["haymana"] = "Haymana, Ankara'nın güneybatısındaki bozkır ve termal ilçesidir; merkezden yaklaşık 65 km uzaklıktadır. İstanbul güzergâhı için Çankaya üzerinden Çevre Yolu'na bağlanılmakta olup toplam mesafe Ankara merkez ilçeleriyle karşılaştırılabilir düzeydedir. Kış aylarında yaylaların karla kapandığı dönemlerde erken çıkış zorunludur.",
        ["evren"] = "Evren, Ankara'nın en küçük ilçesi olup coğrafi konumu itibariyle Kırıkkale ile Ankara'nın sınır bölgesinde yer almaktadır. İlçe merkezine erişim, dar ve kısmen engebeli yollardan sağlandığından her türlü taşımada 3,5 ton kamyonet standart çözümdür. Büyük araçlar ilçe girişinde bekleme yaparak ikincil araç koordinasyonu ile iç transferi tamamlamaktadır.",
        ["kalecik"] = "Kalecik, Kızılırmak vadisinde bağcılığıyla tanınan ve Ankara'ya yaklaşık 75 km uzaklıktaki küçük bir ilçedir. Kale ve vadideki tarihi konut dokusunda dar sokaklar nedeniyle büyük kamyon erişimi kısıtlıdır; kamyonet bu bölge için en uygun çözüm olmaktadır. İstanbul güzergâhı için Akyurt üzerinden kuzey Ankara Çevre Yolu'na ulaşılmaktadır.",
        ["sereflikocehisar"] = "Şereflikoçhisar, Tuz Gölü kıyısındaki ve Ankara merkezine yaklaşık 115 km mesafedeki güneydoğu ilçesidir. Bu uzaklık, taşıma maliyetlerine Ankara merkez ilçelerine kıyasla %20–30 arasında ek yansıyabilir; bu durum keşif aşamasında şeffaf biçimde müşteriyle paylaşılmaktadır. İstanbul'a giden araçlar Ankara Çevre Yolu'na çıkarak TEM'e bağlanmaktadır.",
    };

    private static readonly Dictionary<(string Ilce, ServisTipi Servis), string> ServisDetaylar = new()
    {
        // ── ÇANKAYA ──
        [("cankaya", ServisTipi.Kamyonet)]      = "Kavaklidere ve Oran'ın site ve apartman girişlerinde güvenlik geçişi ve yükleme noktası önceden yönetimle koordine edilmekte; 3,5 ton kamyonetimiz dar site içi yollarda ve otoparkların rampa girişlerinde sorunsuz manevra yapabilmektedir. Çukurambar ve GOP'taki modern rezidans yapılarında ise yük asansörü ön rezervasyonu ile yükleme verimli biçimde tamamlanmaktadır.\n\nKızılay ve Bahçelievler'deki eski konut stokunda asansör yoksa kat başına ekip planlaması yapılmakta; büyük mobilyalar merdivenden güvenle çıkarılmaktadır. Çankaya'nın Çevre Yolu'na bağlantısı TEM'e kısa sürede ulaşmayı sağlamakta; sabah 06:30 kalkışla İstanbul'a öğleden önce varılmaktadır.",
        [("cankaya", ServisTipi.Sehirlerarasi)] = "Çankaya, Ankara'nın merkezi ilçesi olarak Çevre Yolu bağlantısıyla TEM'e hızla çıkabilen güzergâh avantajına sahiptir. Balgat ve GOP'taki residence ve apartmanlarda sabah 06:30–07:00 yüklemesiyle araç Ankara trafiği yoğunlaşmadan İstanbul'a yola çıkmakta; aynı gün teslimat standart olarak tamamlanmaktadır.\n\nTüm eşyalar yükleme öncesinde envanter listesiyle fotoğraflanmakta ve nakliye sigortasına dahil edilmektedir. Çankaya'dan İstanbul'un Kadıköy, Beşiktaş, Şişli ve Ataşehir gibi tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat gerçekleştirilmektedir.",
        [("cankaya", ServisTipi.EvdenEve)]      = "Bahçelievler, Emek ve Kızılay mahallelerindeki çok katlı yapılarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması planlanmaktadır. Kat başına taşıma süresi keşifte netleştirilmekte; her eşya balonlu naylon ve battaniye ambalajıyla korunarak İstanbul yoluna hazırlanmaktadır.\n\nOran ve Çayyolu'nun büyük sitelerinde yük asansörü planlamasıyla yükleme verimli biçimde tamamlanmaktadır. İstanbul'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirerek müşterinin aynı gün yerleşmesini sağlamaktadır.",
        [("cankaya", ServisTipi.Ofis)]          = "Kızılay, Çukurambar ve GOP iş merkezlerinden İstanbul'a kurumsal taşımalarda gece ya da hafta sonu nakliyat tercih edilmekte; pazartesi sabahı personel çalışmaya hazır ofiste başlamaktadır. IT ekipmanı anti-statik ambalaj, sunucular özel koruyucu kasada iletilmekte; kablo düzeni fotoğraflanarak Ankara'daki kurulum planı İstanbul'da yeniden oluşturulmaktadır.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("cankaya", ServisTipi.Fuar)]          = "Çankaya'daki reklam, medya ve teknoloji firmalarının İstanbul CNR veya Tüyap fuar alanlarına gönderilen stand profilleri, display paneller ve promosyon materyalleri darbe emici ambalajlarla hazırlanmaktadır. Grafik baskılar rulo koliler içinde, ekranlar özel köpük kesim kasalarda iletilmektedir.\n\nFuar açılışından 2 gün önce teslimat taahhüt edilmektedir. Fuar sonrası geri taşıma rezervasyonu ilk operasyonla eş zamanlı yapılarak sezon yoğunluğunda yer güvencesi sağlanmaktadır.",
        [("cankaya", ServisTipi.Kamyon)]        = "Oran, Çayyolu ve Keklikpınarı'ndaki büyük sitelerin 3+1–4+1 dairelerinden İstanbul'a 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, tüm mobilyayı tek araçta konsolide ederek ek sefer maliyetinden kaçınmaktadır. Geniş site araç yolları kamyon yüklemesini kolaylaştırmaktadır.\n\nTüm eşyalar hareket öncesinde envanter fotoğrafıyla belgelenerek sigorta kapsamına alınmaktadır. İstanbul'a varışta ekib eşyaları odaya taşımakta ve büyük mobilyaları monte etmektedir.",
        [("cankaya", ServisTipi.Parsiyel)]      = "Çankaya'dan İstanbul'a birkaç parça mobilya, kargo kutusu veya az miktarda eşya göndermek için parsiyel araç hizmeti, tam araç maliyetinin çok altında ekonomik çözüm sunmaktadır. Düzenli İstanbul seferi güzergâhındaki konsolide yüklemeye dahil edilen gönderiler zamanında teslim edilmektedir.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü müşteriye önceden bildirilmektedir. Kırılgan parçalar için ek ambalaj seçeneği geçerlidir.",
        [("cankaya", ServisTipi.Ambar)]         = "Çankaya'daki konutunu boşaltıp İstanbul'daki yeni ev teslimini bekleyen müşteriler için eşyalar güvenli depomuzda kilitli, kontrollü alanda tutulmaktadır. Depolama süresi haftalık ya da aylık dönemler hâlinde esnek biçimde planlanabilmektedir.\n\nÇıkışta eşyalar İstanbul adresine taşınmakta; taşıma ücreti o tarihin tarife fiyatına göre önceden bildirilmektedir. Depo tesisi kamera sistemi, nem kontrolü ve yangın önlemiyle donatılmıştır.",

        // ── KEÇİÖREN ──
        [("kecioren", ServisTipi.Kamyonet)]      = "Etlik ve Bağlum'daki toplu konut bloklarının bazı dar arka sokaklarında 3,5 ton kamyonetimiz büyük araçlara kıyasla belirgin manevra avantajı sağlamaktadır; bina önü duraklama noktası önceden belirlenerek hızlı yükleme gerçekleştirilmektedir. Kalaba'daki yüksek katlı yapılarda ise asansör ön rezervasyonu ve komşu koordinasyonuyla yükleme verimli biçimde tamamlanmaktadır.\n\nKeçiören TOKİ bloklarının geniş girişleri büyük mobilyaların sorunsuz çıkarılmasına imkân tanımaktadır. Çevre Yolu'na bağlantı Keçiören aksından sağlanmakta; sabah 06:30 kalkışla İstanbul'a öğleden önce varılmaktadır.",
        [("kecioren", ServisTipi.Sehirlerarasi)] = "Keçiören, Ankara'nın en kalabalık ilçesi olarak Çevre Yolu bağlantısıyla TEM'e hızla çıkabilen güzergâh üzerindedir. Merkez ve Kalaba'dan sabah 06:30 yüklemesiyle araç trafik yoğunlaşmadan önce İstanbul'a yola çıkmakta; aynı gün teslimat standart olarak tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Keçiören'den İstanbul'un tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat gerçekleştirilmektedir.",
        [("kecioren", ServisTipi.EvdenEve)]      = "Kuşcağız ve Aktepe mahallelerindeki konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nBağlum ve Etlik'teki eski konut stokunda asansör yoksa kat başına ekip planlaması yapılmaktadır. İstanbul'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("kecioren", ServisTipi.Ofis)]          = "Keçiören'deki muhasebe, hukuk ve sağlık klinikleri ile küçük ticaret firmalarının İstanbul taşımalarında IT ekipmanı anti-statik ambalajla paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("kecioren", ServisTipi.Fuar)]          = "Keçiören'den İstanbul fuar alanlarına taşınan stand sistemleri ve promosyon materyalleri darbe emici ambalajlarla hazırlanmaktadır. Çevre Yolu–TEM güzergâhının güvenilir bağlantısı fuar tarihinden 2 gün önce teslimat taahhüdünü desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("kecioren", ServisTipi.Kamyon)]        = "Bağlum ve Keçiören Merkez'deki 3+1 ve daha büyük konutlardan İstanbul'a 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, birden fazla kamyonet seferine kıyasla hem daha ekonomik hem daha güvenlidir. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak Çevre Yolu–TEM güzergâhından İstanbul yoluna girilmektedir. İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("kecioren", ServisTipi.Parsiyel)]      = "Keçiören'den İstanbul'a az eşya veya birkaç parça mobilya göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü 2–3 gün öncesinden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("kecioren", ServisTipi.Ambar)]         = "Keçiören'deki konutunu boşaltıp İstanbul'daki yeni ev teslimini bekleyen müşteriler eşyalarını güvenli, kilitli depomuzda muhafaza edebilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── YENİMAHALLE ──
        [("yenimahalle", ServisTipi.Kamyonet)]      = "Demetevler ve Şentepe'nin yüksek katlı konut bloklarında 3,5 ton kamyonetimiz asansör ön rezervasyonu ve komşu koordinasyonuyla verimli yükleme tamamlamaktadır. Batıkent'in planlı konut alanlarında ise geniş bina girişleri büyük mobilyaların sorunsuz çıkarılmasını sağlamaktadır.\n\nTEM'e Yenimahalle aksından olan kısa mesafe, yükleme tamamlanır tamamlanmaz aracın Ankara trafiğine girmeden İstanbul yoluna çıkmasını mümkün kılmaktadır. Sabah 06:30 kalkışla öğleden önce İstanbul varışı rahatlıkla sağlanmaktadır.",
        [("yenimahalle", ServisTipi.Sehirlerarasi)] = "Yenimahalle, Ankara ilçeleri arasında TEM'e en kısa bağlantıyı sunan ilçelerden biridir; bu coğrafi konum şehirlerarası taşımalarda rakipsiz güzergâh avantajı sağlamaktadır. Sabah 06:30 yüklemesiyle araç Ankara trafiğine hiç girmeden TEM'e bağlanmakta; aynı gün İstanbul teslimatı standart olarak tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Yenimahalle'den İstanbul'un tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat gerçekleştirilmektedir.",
        [("yenimahalle", ServisTipi.EvdenEve)]      = "Batıkent ve Ostim çevresindeki planlı konut alanlarında asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nGeniş bina girişleri büyük mobilyaların sorunsuz çıkarılmasına imkân tanımakta; gün içinde İstanbul'a varışta monte ve odaya yerleştirme hizmeti dahil olmaktadır.",
        [("yenimahalle", ServisTipi.Ofis)]          = "Ostim OSB'deki firma ofisleri ve İvedik'teki sanayi işletmelerinin İstanbul'a kurumsal taşımalarında IT ekipmanı etiketli ve protokollü biçimde paketlenmekte; sunucular özel koruyucu kasalarda iletilmektedir. Hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır.\n\nKurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır. Pazartesi sabahı personel çalışmaya hazır ofiste başlamaktadır.",
        [("yenimahalle", ServisTipi.Fuar)]          = "Yenimahalle'deki teknik donanım ve sanayi firmalarının İstanbul fuar alanlarına taşınan ekipmanları vibrasyon emici ambalajlarla korunmaktadır. TEM'e kısa mesafedeki konum fuar öncesi 2 gün teslimat taahhüdünü güçlü biçimde desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("yenimahalle", ServisTipi.Kamyon)]        = "İvedik'teki sanayi işletmelerinden ve Batıkent'teki büyük konutlardan İstanbul'a 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, TEM'e en kısa güzergâhtan geçmektedir. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak TEM'e hızla bağlanılmaktadır. İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("yenimahalle", ServisTipi.Parsiyel)]      = "Yenimahalle'den İstanbul'a öğrenci, bekar veya az eşyalı taşımalar için parsiyel araç hizmeti haftada düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("yenimahalle", ServisTipi.Ambar)]         = "Yenimahalle'deki konutunu veya ofisini boşaltıp İstanbul'a geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli depomuzda kilitli alanda tutulmaktadır. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── MAMAK ──
        [("mamak", ServisTipi.Kamyonet)]      = "Tuzluçayır ve Hüseyingazi'nin eğimli mahalle dokusundaki dar yollarda 3,5 ton kamyonetimiz büyük araçlara kıyasla belirgin manevra ve erişim avantajı sağlamaktadır; bina önü duraklama noktası önceden belirlenerek hızlı yükleme gerçekleştirilmektedir. Mamak Merkez'in yüksek katlı yapılarında ise asansör koordinasyonuyla yükleme verimli biçimde tamamlanmaktadır.\n\nÇankaya aksına çıkışla Çevre Yolu'na bağlantı sağlanmakta; sabah 06:30 kalkışla İstanbul'a öğleden önce varılmaktadır. Eğimli arazi nedeniyle yükleme öncesinde araç konumlanma noktası özellikle önem taşımaktadır.",
        [("mamak", ServisTipi.Sehirlerarasi)] = "Mamak'tan Çankaya aksına geçen araç Ankara Çevre Yolu'nu kullanarak TEM'e bağlanmakta; sabah 06:30 yüklemesiyle aynı gün İstanbul teslimatı tamamlanmaktadır. İlçenin eğimli yapısı gözetilerek yükleme saati ve araç konumlanma noktası önceden planlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Mamak'tan İstanbul'un tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("mamak", ServisTipi.EvdenEve)]      = "Mamak Merkez ve Kutlu mahallelerindeki çok katlı konutlarda asansör ön rezervasyonu ve söküm-montaj ekibi koordinasyonuyla kapsamlı ev taşıması gerçekleştirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; kat başına taşıma süresi keşifte önceden hesaplanmaktadır.\n\nTuzluçayır ve Hüseyingazi'deki eski konut stokunda asansör yoksa kat başına ekip planlaması yapılmaktadır. İstanbul'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("mamak", ServisTipi.Ofis)]          = "Mamak'taki küçük ve orta ölçekli işletmelerin İstanbul ofis taşımalarında IT ekipmanı anti-statik ambalajla paketlenmekte; hafta sonu veya gece çalışmayla iş sürekliliği korunmaktadır. Pazartesi sabahı çalışmaya hazır ofis teslim edilmektedir.\n\nArşiv belgeleri kilitli kolilere konulmakta; teslimatta imzalı tutanak düzenlenmektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("mamak", ServisTipi.Fuar)]          = "Mamak'taki üretim ve distribütörlük firmalarının İstanbul fuar alanlarına taşınan ürün ve teşhir materyalleri darbe emici ambalajlarla hazırlanmaktadır. Çevre Yolu–TEM güzergâhının güvenilir bağlantısı fuar öncesi 2 gün teslimat taahhüdünü desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("mamak", ServisTipi.Kamyon)]        = "Mamak'taki 3+1 ve büyük dairelerden İstanbul'a 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, geniş arterlere yakın yükleme noktası seçilerek verimli yürütülmektedir. Tüm eşyalar sigorta kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak Çankaya aksından TEM'e bağlanılmaktadır. İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("mamak", ServisTipi.Parsiyel)]      = "Mamak'tan İstanbul'a birkaç parça mobilya veya kargo göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("mamak", ServisTipi.Ambar)]         = "Mamak'taki konutunu boşaltıp İstanbul'a geçiş tarihi netleşmemiş müşteriler için eşyalar güvenli depomuzda kilitli alanda tutulmaktadır. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── ETİMESGUT ──
        [("etimesgut", ServisTipi.Kamyonet)]      = "Eryaman TOKİ'nin büyük blok girişleri ve geniş park alanları hem kamyonet hem kamyon operasyonları için ideal ortam sunmaktadır; site yönetimiyle yükleme saati ve araç noktası önceden koordine edilmektedir. Elvankent ve Göksu'daki modern sitelerde yük asansörü planlamasıyla büyük mobilyalar verimli biçimde çıkarılmaktadır.\n\nBatı Çevre Yolu'na olan kısa mesafe sayesinde yükleme tamamlanır tamamlanmaz araç TEM'e hızla bağlanmakta; sabah 06:30 kalkışla İstanbul'a öğleden önce varılmaktadır.",
        [("etimesgut", ServisTipi.Sehirlerarasi)] = "Etimesgut, Batı Çevre Yolu bağlantısıyla TEM'e en hızlı çıkış imkânı sunan Ankara ilçelerinden biridir. Şehirlerarası araçlar Ankara trafik saatlerinden etkilenmeden sabah 06:30–07:00 yüklemesiyle İstanbul'a yola çıkmakta; aynı gün teslimat standart olarak tamamlanmaktadır.\n\nTüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir. Etimesgut'tan İstanbul'un tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat gerçekleştirilmektedir.",
        [("etimesgut", ServisTipi.EvdenEve)]      = "Elvankent ve Göksu'daki büyük sitelerde kapıcı ve site yönetimi iletişimi ekibimiz tarafından önceden sağlanmakta; asansör ön rezervasyonu ve komşu koordinasyonuyla yükleme günü aksaksız yürütülmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nEryaman TOKİ bloklarının geniş girişleri büyük mobilyaların sorunsuz çıkarılmasına imkân tanımaktadır. İstanbul'daki yeni konuta varışta ekib mobilyaları monte etmekte ve eşyaları odaya yerleştirmektedir.",
        [("etimesgut", ServisTipi.Ofis)]          = "Etimesgut'taki teknoloji ve mühendislik firmalarının İstanbul ofis taşımalarında IT altyapısı güvenli biçimde demonte edilmekte; sunucu, ağ cihazı ve UPS üniteler özel koruyucu kasalarda iletilmektedir. Kablo düzeni fotoğraflanarak İstanbul'daki kurulum kolaylaştırılmaktadır.\n\nHafta sonu veya gece taşımayla iş sürekliliği korunmakta; kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("etimesgut", ServisTipi.Fuar)]          = "Etimesgut'taki OEM ve distribütörlük firmalarının İstanbul fuar alanlarına taşınan ekipman ve teşhir materyalleri vibrasyon emici ambalajlarla güvence altına alınmaktadır. Batı Çevre Yolu–TEM bağlantısının güvenilir güzergâhı fuar öncesi 2 gün teslimat taahhüdünü desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("etimesgut", ServisTipi.Kamyon)]        = "Eryaman'daki 4+1 ve villa tarzı büyük konutlardan İstanbul'a 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma, Batı Çevre Yolu güzergâhının avantajını tam kullanmaktadır. Geniş site araç yolları kamyon yüklemesini kolaylaştırmakta; tüm eşyalar envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak TEM'e Batı Çevre Yolu'ndan bağlanılmaktadır. İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("etimesgut", ServisTipi.Parsiyel)]      = "Etimesgut'tan İstanbul'a az eşya veya birkaç parça mobilya göndermek için parsiyel araç hizmeti haftada düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("etimesgut", ServisTipi.Ambar)]         = "Elvankent'teki konutunu teslim edip İstanbul'daki anahtar teslimini bekleyen müşteriler eşyalarını güvenli depomuzda kilitli alanda muhafaza edebilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── SİNCAN ──
        [("sincan", ServisTipi.Kamyonet)]      = "Pirinçlik ve Fatih mahallelerindeki yüksek katlı konut sitelerine 3,5 ton kamyonetimiz sabah saatlerinde kolayca erişmektedir; asansörlü binalarda yükleme ekibi kapıdan kapıya koordinasyonu verimle yürütmektedir. Dar mahalle aralarındaki eski yapılarda kamyonet boyutu büyük mobilyaların çıkarılmasında standart avantaj sağlamaktadır.\n\nSincan'ın TEM'e fiilen bitişik konumu sayesinde yükleme tamamlanır tamamlanmaz araç Ankara trafiğine girmeden İstanbul güzergâhına çıkmaktadır. Sabah 06:30 kalkışla İstanbul'un merkezi ilçelerine öğleden önce rahatça varılmakta; gecikme riski en düşük hatlardandır.",
        [("sincan", ServisTipi.Sehirlerarasi)] = "Sincan'ın TEM girişine fiilen bitişik konumu şehirlerarası araçların Ankara trafiğine hiç girmeden İstanbul'a yola çıkmasına olanak tanımaktadır; bu coğrafi avantaj Ankara ilçeleri arasında rakipsizdir. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nSabah 06:30 yüklemesiyle araç TEM'e 5 dakikada bağlanmakta; avrupa yakasına öğleden önce, anadolu yakasına ise öğle saatlerinde ulaşılmaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak uygulanmaktadır.",
        [("sincan", ServisTipi.EvdenEve)]      = "Pirinçlik ve Anıt mahallelerindeki yüksek katlı konutlarda asansör planlaması, komşu koordinasyonu ve yükleme saati yönetimiyle taşınma günü hızlı ve sessiz yürütülmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nSincan'ın TEM'e yakınlığı aynı gün İstanbul teslimatını standart kılmaktadır. Varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("sincan", ServisTipi.Ofis)]          = "Sincan OSB'deki firmaların İstanbul ofis veya tesis taşımalarında IT altyapısı güvenli biçimde demonte edilmekte; sunucu, ağ cihazı ve UPS üniteler özel koruyucu kasalarda iletilmektedir. Kablo düzeni fotoğraflanarak İstanbul'daki yeniden kurulum kolaylaştırılmaktadır.\n\nTEM'e yakın konum hafta sonu veya gece taşıma seçeneğini de desteklemekte; iş sürekliliği korunmaktadır. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak düzenlenmektedir.",
        [("sincan", ServisTipi.Fuar)]          = "Sincan OSB'deki üretici firmaların İstanbul fuar alanlarına taşınan stand, ekipman ve teşhir materyalleri vibrasyon emici ambalajlarla güvence altına alınmaktadır. TEM'e olan kısa mesafe fuar öncesi 2 gün teslimat taahhüdünü desteklemektedir.\n\nFuar sonrası geri taşıma rezervasyonu önceden alındığında öncelikli araç tahsisi yapılmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmakta; teşhir materyallerinin güvenliği esas alınmaktadır.",
        [("sincan", ServisTipi.Kamyon)]        = "Sincan'daki 3+1 ve 4+1 dairelerden İstanbul'a 12–18 ton kapalı kasalı kamyon ile tek seferlik taşıma TEM'e olan minimum mesafeyi tam kullanmaktadır. Geniş site araç yolları kamyon yüklemesini kolaylaştırmakta; tüm eşyalar envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak TEM'e doğrudan bağlanılmaktadır. İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("sincan", ServisTipi.Parsiyel)]      = "Sincan'dan İstanbul'a az eşya veya birkaç parça mobilya göndermek için parsiyel araç hizmeti haftada düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü önceden bildirilmektedir.\n\nTEM'e yakın konum sayesinde parsiyel araç Ankara trafiğine girmeden hızla güzergâha çıkmaktadır. Kırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("sincan", ServisTipi.Ambar)]         = "Sincan'daki konutunu teslim edip İstanbul'daki anahtar teslimini bekleyen müşteriler eşyalarını güvenli depomuzda kilitli alanda muhafaza edebilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.",

        // ── ALTINDAĞ ──
        [("altindag", ServisTipi.Kamyonet)]      = "Hamamönü ve Ulus'un dar tarihi sokak dokusunda 3,5 ton kamyonetimiz standart büyük araçların ulaşamadığı pek çok adrese sorunsuz erişim sağlamaktadır; ekibimiz bu bölgeye özgü güzergâh bilgisine sahiptir. Çiçek ve Atıfbey mahallelerindeki yüksek katlı konutlarda asansör planlaması ile hızlı yükleme gerçekleştirilmektedir.\n\nYükleme tamamlanır tamamlanmaz araç Çankaya aksından Çevre Yolu'na çıkmakta ve TEM'e kısa sürede bağlanmaktadır. Sabah 06:30 kalkışla İstanbul'un tüm merkezi ilçelerine aynı gün kapıdan kapıya teslimat sağlanmaktadır.",
        [("altindag", ServisTipi.Sehirlerarasi)] = "Altındağ Merkez'den sabah erken yüklemeyle başlayan taşıma Çankaya aksından Çevre Yolu'na çıkarak TEM'e bağlanmakta; İstanbul'a aynı gün teslimat standart olarak tamamlanmaktadır. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nUlus ve Anafartalar bölgesindeki konut ile iş yeri taşımalarında ticari araç yönlendirmesi tecrübeli ekibimizce yapılmaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("altindag", ServisTipi.EvdenEve)]      = "Çiçek ve Atıfbey mahallelerindeki yüksek katlı konutlarda asansör koordinasyonu ve komşu bilgilendirmesiyle yükleme günü hızlı ve sessiz yürütülmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; kırılgan parçalar için özel kasa kullanılmaktadır.\n\nHamamönü'nün dar sokak dokusunda büyük mobilyaların çıkarılması için önceden yol ölçümü yapılmaktadır. İstanbul'daki yeni konuta varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("altindag", ServisTipi.Ofis)]          = "Anafartalar ticaret bölgesindeki işletme taşımalarında ticari araç gece kısıtlamalarına uygun saat planlaması yapılmakta; hafta içi gece veya hafta sonu seçeneği sunulmaktadır. IT altyapısı demonte edilerek özel koruyucu kasalarda iletilmektedir.\n\nKablo düzeni fotoğraflanarak İstanbul'daki yeniden kurulum kolaylaştırılmaktadır. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak düzenlenmektedir.",
        [("altindag", ServisTipi.Fuar)]          = "Altındağ'daki üretim ve satış firmalarının İstanbul fuar taşımalarında ürün ve teşhir materyalleri için titiz paketleme uygulanmakta; vibrasyon emici ambalajlarla hasar riski minimize edilmektedir. Erken rezervasyonla tercih edilen fuar tarihi güvence altına alınmaktadır.\n\nFuar sonrası geri taşıma için aynı güzergâh ve ekip planlanmakta; eşyalar İstanbul'dan Altındağ adresine iade edilmektedir. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("altindag", ServisTipi.Kamyon)]        = "Altındağ'ın yüksek katlı sosyal konut yapılarından 3+1 daire taşımaları 12 ton kapalı kasalı kamyon ile tek seferde tamamlanmaktadır. Çankaya aksından Çevre Yolu'na çıkış bu güzergâhta güvenilirdir; tüm eşyalar envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak TEM'e kısa sürede bağlanılmaktadır. İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("altindag", ServisTipi.Parsiyel)]      = "Altındağ'dan İstanbul'a birkaç parça eşya veya kargo gönderimi için parsiyel araç hizmeti haftada düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir; toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("altindag", ServisTipi.Ambar)]         = "Altındağ'daki konut veya iş yerinden çıkıp İstanbul'a geçiş tarihini bekleyen müşteriler için haftalık ya da aylık esnek depolama hizmeti sunulmaktadır. Eşyalar güvenli depomuzda kilitli alanda, kamera ve nem kontrolü altında muhafaza edilmektedir.\n\nÇıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",

        // ── GÖLBAŞI ──
        [("golbasi", ServisTipi.Kamyonet)]      = "Mogan Gölü çevresindeki villa ve müstakil konutlardan taşınan antika, değerli tablo veya tasarım mobilyalar özel battaniye ve balonlu ambalajla korunarak 3,5 ton kamyonetimizle İstanbul'a ulaştırılmaktadır. Site içi araç erişimi ve kapı genişliği önceden değerlendirilerek yükleme günü sürprizler önlenmektedir.\n\nGölbaşı'ndan Konya yolu üzerinden Çevre Yolu'na bağlanan güzergâh sabah 07:00'de erken trafik öncesinde çıkışa en uygun saati sunmaktadır. Sabah yüklemesiyle İstanbul'a öğleden önce varılmakta; kapıdan kapıya teslimat tamamlanmaktadır.",
        [("golbasi", ServisTipi.Sehirlerarasi)] = "Gölbaşı'ndan Konya yolu üzerinden Çevre Yolu'na bağlanan güzergâh sabah 07:00'de erken trafik öncesinde çıkışa en uygun rotayı sunmaktadır. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nVilla büyüklüğündeki konutların eşya hacmi için 12–18 ton kamyon kapasitesi de kısa sürede devreye alınmaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("golbasi", ServisTipi.EvdenEve)]      = "Mogan Gölü çevresindeki villaların geniş eşya hacmini kapsayan ev taşımalarında 12 ton kamyon kapasitesiyle tek seferlik nakliyat sağlanmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; değerli parçalar için ayrı koruyucu kasa kullanılmaktadır.\n\nSite ve villa çıkışlarında kapıcı ve yönetim koordinasyonu önceden gerçekleştirilmektedir. İstanbul'daki yeni konuta varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("golbasi", ServisTipi.Ofis)]          = "Gölbaşı'ndaki teknopolis ve serbest bölge firmalarının İstanbul ofis taşımalarında IT altyapısı güvenli biçimde demonte edilmekte; sunucu, ağ cihazı ve UPS üniteler özel koruyucu kasalarda iletilmektedir. Kablo düzeni fotoğraflanarak İstanbul'daki yeniden kurulum kolaylaştırılmaktadır.\n\nHafta sonu veya gece taşımayla iş sürekliliği korunmakta; kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("golbasi", ServisTipi.Fuar)]          = "Gölbaşı'ndaki ihracat ve teknoloji firmalarının İstanbul fuar alanlarına taşınan ekipman ve teşhir materyalleri vibrasyon emici ambalajlarla güvence altına alınmaktadır. Erken rezervasyonla tercih edilen fuar tarihi için araç tahsisi yapılmakta; 2 gün öncesi teslimat taahhüdü verilmektedir.\n\nFuar sonrası geri taşıma için aynı ekip ve güzergâh devreye girmektedir. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("golbasi", ServisTipi.Kamyon)]        = "Mogan çevresindeki 4+1 ve villa konutlardan İstanbul'a 18 ton kapalı kasalı kamyon ile büyük mobilya taşıması tek seferde tamamlanmaktadır. Konya yolu üzerinden Çevre Yolu'na bağlanan güzergâh kamyon trafiğine uygun geniş şeritler sunmaktadır.\n\nYükleme sabah 07:00'de başlatılmakta; tüm eşyalar envanter listesiyle belgelenmektedir. İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("golbasi", ServisTipi.Parsiyel)]      = "Gölbaşı'ndan İstanbul'a az eşya veya birkaç parça mobilya göndermek için parsiyel araç hizmeti haftanın belirli günleri düzenli sefer yapmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; gönderim tarihi önceden bildirilmektedir.\n\nKırılgan ve değerli parçalar için ek ambalaj seçeneği mevcuttur. Toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("golbasi", ServisTipi.Ambar)]         = "Gölbaşı'ndan taşınan eşyalar İstanbul konuta hazır olana kadar klimalı, kamera denetimli ve güvenlikli depolarda saklanmaktadır. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",

        // ── PURSAKLAR ──
        [("pursaklar", ServisTipi.Kamyonet)]      = "Pursaklar İstasyon ve Saray mahallelerindeki yeni konut sitelerinde asansörlü binalar hızlı ve verimli yükleme sağlamaktadır; 3,5 ton kamyonetimiz geniş site araç yollarında rahatlıkla manevra yapabilmektedir. Site güvenlik geçişi ve yükleme noktası önceden koordine edilmektedir.\n\nPursaklar'dan Keçiören aksına geçiş sonrasında araç Çevre Yolu'na kısa sürede bağlanmakta; İstanbul'a aynı gün teslimat standart olarak tamamlanmaktadır. Sabah 06:30 kalkışla öğleden önce İstanbul merkezi ilçelerine ulaşılmaktadır.",
        [("pursaklar", ServisTipi.Sehirlerarasi)] = "Pursaklar'dan Keçiören aksına geçiş sonrasında Çevre Yolu'na çıkılmakta; şehirlerarası araç Ankara trafiğine girmeden İstanbul güzergâhına bağlanmaktadır. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nSabah 06:30 kalkışla avrupa yakasına öğleden önce, anadolu yakasına öğle saatlerinde ulaşılmaktadır. Kapıdan kapıya hizmet her adrese standart olarak uygulanmaktadır.",
        [("pursaklar", ServisTipi.EvdenEve)]      = "Karacaören ve Hacıhasan mahallelerindeki konutlarda tam kapsamlı ev taşıma hizmeti ambalaj ve montaj dahil sunulmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nPursaklar'ın Keçiören bağlantısı sayesinde evden eve taşıma aynı gün İstanbul'da tamamlanmaktadır. Varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("pursaklar", ServisTipi.Ofis)]          = "Pursaklar'daki ticari işletmelerin İstanbul ofis taşımalarında IT ekipmanı güvenli biçimde demonte edilmekte; arşiv kutularının taşınması standart kurumsal paket içinde yer almaktadır. Kablo düzeni fotoğraflanarak yeniden kurulum kolaylaştırılmaktadır.\n\nHafta sonu veya gece taşımayla iş sürekliliği korunmakta; kurumsal fatura ve sigorta belgesi her taşımada standart olarak düzenlenmektedir.",
        [("pursaklar", ServisTipi.Fuar)]          = "Pursaklar'daki firmalar için İstanbul fuarlarına yönelik stand ve ekipman taşımalarında fuar tarihi bazlı esnek planlama yapılmaktadır. Vibrasyon emici ambalajlarla teşhir materyalleri güvence altına alınmaktadır.\n\nFuar öncesi 2 gün teslimat taahhüdü verilmekte; fuar sonrası geri taşıma için aynı ekip planlanmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("pursaklar", ServisTipi.Kamyon)]        = "Pursaklar'ın yeni konut sitelerindeki 3+1 ve 4+1 dairelerden büyük mobilya taşımaları 12 ton kapalı kasalı kamyon ile tek seferde tamamlanmaktadır. Geniş site araç yolları kamyon yüklemesini kolaylaştırmakta; tüm eşyalar envanter listesiyle belgelenmektedir.\n\nYükleme sabah 06:30'da başlatılarak Çevre Yolu'na kısa sürede bağlanılmaktadır. İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("pursaklar", ServisTipi.Parsiyel)]      = "Pursaklar'dan İstanbul'a az eşya göndermek için parsiyel araç hizmeti 2 gün öncesinden rezervasyonla planlanmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir. Toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("pursaklar", ServisTipi.Ambar)]         = "Pursaklar'daki eşyalar kısa ya da uzun süreli depolama seçeneğiyle güvenli depomuza alınmakta; İstanbul'a hazır olunduğunda ekibimizle teslim edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nDepo tesisi kamera ve nem kontrol sistemiyle donatılmıştır. Çıkışta taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",

        // ── POLATLI ──
        [("polatli", ServisTipi.Kamyonet)]      = "Polatlı Merkez ve Yenikent mahallelerinden İstanbul'a kamyonet taşıması yaklaşık 500 km güzergâh nedeniyle sabah 06:00–06:30 gibi erken başlatılmaktadır; mesafe avantajı keşif aşamasında şeffafça aktarılmaktadır. 3,5 ton kamyonetimiz geniş bulvarlarda ve dar mahalle girişlerinde eşit rahatlıkla manevra yapabilmektedir.\n\nKonya yolu üzerinden TEM'e bağlanan güzergâh kullanılarak İstanbul'a aynı gün teslimat sağlanmaktadır. Yükleme tamamlanır tamamlanmaz araç Ankara trafiğine girmeden güzergâha çıkmaktadır.",
        [("polatli", ServisTipi.Sehirlerarasi)] = "Polatlı'dan İstanbul'a şehirlerarası nakliyat yaklaşık 500 km güzergâh nedeniyle fiyat ve süre açısından Ankara merkez ilçelerinden farklılaşmaktadır; keşif aşamasında net bilgi verilmektedir. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nSabah 06:30 kalkışla araç Konya yolundan TEM'e bağlanmakta; İstanbul'a aynı gün öğleden sonra teslimat tamamlanmaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("polatli", ServisTipi.EvdenEve)]      = "Polatlı'nın Seymen ve Yenikent mahallelerindeki evlerden erken yükleme başlangıcıyla aynı gün İstanbul'a kapıdan kapıya teslimat yapılabilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nPolatlı'nın ek mesafe faktörü nedeniyle yükleme saatinin en geç 07:00'ye kadar başlatılması önerilmektedir. İstanbul'daki yeni konuta varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("polatli", ServisTipi.Ofis)]          = "Polatlı'daki tarımsal ekipman, savunma sanayi ve ticaret firmalarının İstanbul ofis taşımalarında geniş araç kapasitesi ve esnek tarih seçeneği sunulmaktadır. IT altyapısı güvenli biçimde demonte edilmekte; sunucu ve ağ cihazları özel koruyucu kasalarda iletilmektedir.\n\nHafta sonu veya erken sabah hareketiyle iş sürekliliği korunmaktadır. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak düzenlenmektedir.",
        [("polatli", ServisTipi.Fuar)]          = "Polatlı'dan İstanbul fuarlarına uzun mesafe fuar taşımacılığı için önceden rezervasyon ve kesin tarih belirlenmesi gerekmektedir. Ekipman ve teşhir materyalleri vibrasyon emici ambalajlarla güvence altına alınmaktadır.\n\nErken kalkışla fuar alanına zamanında varış sağlanmaktadır. Fuar sonrası geri taşıma için aynı güzergâh ve ekip planlanmakta; hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("polatli", ServisTipi.Kamyon)]        = "Polatlı'dan İstanbul'a büyük konut taşımalarında 12 ton kapalı kasalı kamyon ek mesafe nedeniyle sabah en geç 07:00'de hareket ederek aynı gün teslimata ulaşmaktadır. Tüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir.\n\nKonya yolu üzerinden TEM'e bağlanan güzergâh kamyon trafiğine uygun geniş şeritler sunmaktadır. İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("polatli", ServisTipi.Parsiyel)]      = "Polatlı'dan İstanbul'a parsiyel araç hizmetinde ek mesafe fiyata yansımakta olup bu durum keşiften önce şeffafça bildirilmektedir. Haftalık sefer takviminde Polatlı'ya uygun gün talep bazında belirlenmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir. Toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("polatli", ServisTipi.Ambar)]         = "Polatlı'daki eşyalar İstanbul'daki taşınma tarihine kadar güvenli depomuzda kilitli alanda muhafaza edilmektedir; ek mesafe faktörü depolama hizmetini cazip kılmaktadır. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",

        // ── AKYURT ──
        [("akyurt", ServisTipi.Kamyonet)]      = "Akyurt Merkez ve Karaağaç mahallelerindeki konut alanlarına 3,5 ton kamyonetimiz sabah saatlerinde kolayca ulaşmaktadır; bazı sanayi bölgesi adreslerinde büyük araç altyapısı da hazır tutulmaktadır. Bölgeye özgü güzergâh bilgisine sahip ekibimiz yükleme koordinasyonunu sorunsuz yürütmektedir.\n\nAkyurt'tan Pursaklar aksından kuzey Çevre Yolu'na geçen araç kısa sürede TEM'e bağlanmakta; İstanbul'a aynı gün teslimat standart olarak tamamlanmaktadır. Sabah 06:30 kalkışla öğleden önce İstanbul merkezi ilçelerine ulaşılmaktadır.",
        [("akyurt", ServisTipi.Sehirlerarasi)] = "Akyurt'tan Pursaklar aksından kuzey Çevre Yolu'na geçilerek TEM'e bağlanan araç İstanbul'a aynı gün şehirlerarası teslimatı tamamlamaktadır. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nSabah 06:30 kalkışla avrupa yakasına öğleden önce, anadolu yakasına öğle saatlerinde ulaşılmaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("akyurt", ServisTipi.EvdenEve)]      = "Akyurt'taki konutlarda evden eve taşıma öncesinde eksiksiz keşif yapılarak eşya miktarı ve adres erişimi değerlendirilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nPursaklar bağlantısı sayesinde aynı gün İstanbul teslimatı standart olarak gerçekleştirilmektedir. Varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("akyurt", ServisTipi.Ofis)]          = "Akyurt OSB'deki firmaların İstanbul ofis taşımalarında IT altyapısı güvenli biçimde demonte edilmekte; sunucu, ağ cihazı ve UPS üniteler özel koruyucu kasalarda iletilmektedir. Kablo düzeni fotoğraflanarak İstanbul'daki yeniden kurulum kolaylaştırılmaktadır.\n\nHafta sonu veya gece taşımayla iş sürekliliği korunmakta; kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("akyurt", ServisTipi.Fuar)]          = "Akyurt'taki sanayi firmalarının İstanbul fuar alanlarına taşınan ürün ve teşhir materyalleri sigortalı olarak vibrasyon emici ambalajlarla nakliyatı yapılmaktadır. Erken rezervasyonla fuar tarihi güvence altına alınmaktadır.\n\nFuar öncesi 2 gün teslimat taahhüdü verilmekte; fuar sonrası geri taşıma için aynı ekip planlanmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("akyurt", ServisTipi.Kamyon)]        = "Akyurt'taki 2+1 ve üzeri konutlardan İstanbul'a 12 ton kapalı kasalı kamyon ile tek seferlik taşıma Pursaklar aksından Çevre Yolu güzergâhıyla tamamlanmaktadır. Tüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir.\n\nYükleme sabah 06:30'da başlatılarak TEM'e kısa sürede bağlanılmaktadır. İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("akyurt", ServisTipi.Parsiyel)]      = "Akyurt'tan İstanbul'a birkaç parça eşya göndermek için parsiyel araç hizmeti haftalık düzenli sefer ile sunulmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir. Toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("akyurt", ServisTipi.Ambar)]         = "Akyurt'taki eşyalar İstanbul'a taşınma tarihine kadar güvenli depomuzda kilitli alanda, kamera ve nem kontrolü altında muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",

        // ── ELMADAĞ ──
        [("elmadag", ServisTipi.Kamyonet)]      = "Elmadağ Merkez ve Hasanoğlan'daki sivil konut adreslerine 3,5 ton kamyonetimiz sorunsuz erişim sağlarken askeri bölge sınırları dışındaki güzergâhlardan hareket edilmektedir. Bölgeye özgü rota bilgisine sahip ekibimiz yükleme koordinasyonunu önceden planlayarak gereksiz beklemeleri önlemektedir.\n\nElmadağ'dan Mamak aksından Çankaya Çevre Yolu'na ulaşan araç TEM'e bağlanmakta; İstanbul'a aynı gün şehirlerarası teslimat tamamlanmaktadır. Sabah 06:30 kalkışla öğleden önce merkezi ilçelere ulaşılmaktadır.",
        [("elmadag", ServisTipi.Sehirlerarasi)] = "Elmadağ'dan Mamak aksından Çankaya Çevre Yolu'na ulaşan şehirlerarası araç TEM'e bağlanarak İstanbul'a aynı gün teslimatı tamamlamaktadır. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nSabah 06:30 kalkışla avrupa yakasına öğleden önce, anadolu yakasına öğle saatlerinde ulaşılmaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("elmadag", ServisTipi.EvdenEve)]      = "Balışeyh ve Elmaağaç mahallelerindeki evden eve taşımalar için güzergâh ve adres erişimi önceden planlanmakta; uygun araç boyutu seçilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nMamak bağlantısından TEM'e ulaşan güzergâh aynı gün İstanbul teslimatını mümkün kılmaktadır. Varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("elmadag", ServisTipi.Ofis)]          = "Elmadağ'daki küçük ölçekli işletmelerin İstanbul ofis taşımalarında IT ekipmanı güvenli biçimde demonte edilmekte; arşiv koruması standart kurumsal paket içinde sunulmaktadır. Kablo düzeni fotoğraflanarak yeniden kurulum kolaylaştırılmaktadır.\n\nHafta sonu taşıma seçeneğiyle iş sürekliliği korunmakta; kurumsal fatura ve sigorta belgesi her taşımada standart olarak düzenlenmektedir.",
        [("elmadag", ServisTipi.Fuar)]          = "Elmadağ'daki firmalar için İstanbul fuar taşımalarında teşhir materyalleri özel ambalajla güvence altına alınmakta; zamanında teslimat garantisi verilmektedir. Erken rezervasyonla fuar tarihi için araç tahsisi yapılmaktadır.\n\nFuar sonrası geri taşıma için aynı güzergâh ve ekip planlanmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("elmadag", ServisTipi.Kamyon)]        = "Elmadağ'dan İstanbul'a büyük daire taşımalarında 12 ton kapalı kasalı kamyon ile erken sabah başlayan yükleme aynı gün teslimata olanak tanımaktadır. Tüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir.\n\nMamak aksından Çevre Yolu'na çıkan araç TEM'e kısa sürede bağlanmaktadır. İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("elmadag", ServisTipi.Parsiyel)]      = "Elmadağ'dan İstanbul'a az eşya göndermek için parsiyel araç hizmeti rezervasyona dayalı olarak sunulmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir. Toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("elmadag", ServisTipi.Ambar)]         = "Elmadağ'daki eşyaların depolanması İstanbul'a taşınma tarihinin netleşmesi beklenirken güvenli çözüm sunmaktadır. Eşyalar kamera ve nem kontrolü altındaki kilitli depoda muhafaza edilmektedir.\n\nDepolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir. Çıkışta eşyalar İstanbul adresine ekibimizle teslim edilmektedir.",

        // ── BEYPAZARI ──
        [("beypazari", ServisTipi.Kamyonet)]      = "Beypazarı'ndaki tarihi konak ve yöresel evlerden taşınan antika, değerli porselen ve tasarım mobilyalar özel battaniye ve balonlu ambalajla korunarak 3,5 ton kamyonetimizle İstanbul'a ulaştırılmaktadır. Tarihi dokuya sahip evlerin dar giriş ve kapı ölçüleri önceden değerlendirilerek taşıma planı buna göre hazırlanmaktadır.\n\nBeypazarı'ndan Bolu yolu üzerinden TEM'e bağlanan güzergâh Ankara şehir merkezini tamamen bypass etmekte; taşıma süresi minimize edilmektedir. Sabah kalkışla İstanbul'a aynı gün kapıdan kapıya teslimat tamamlanmaktadır.",
        [("beypazari", ServisTipi.Sehirlerarasi)] = "Beypazarı'ndan Bolu yolu üzerinden TEM'e bağlanan güzergâh Ankara şehir merkezini bypass ederek taşıma süresini optimize etmektedir. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nSabah 06:30 kalkışla araç TEM'e hızla bağlanmakta; İstanbul'a aynı gün öğleden sonra teslimat tamamlanmaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("beypazari", ServisTipi.EvdenEve)]      = "Beypazarı'ndaki tarihi evlerin dar giriş ve kapı ölçüleri için ev taşıma planlaması önceden yapılmakta; hassas mobilyalar için özel paketleme uygulanmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; değerli parçalar için ek koruyucu kasa kullanılmaktadır.\n\nBolu güzergâhının avantajıyla aynı gün İstanbul teslimatı standart olarak gerçekleştirilmektedir. Varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("beypazari", ServisTipi.Ofis)]          = "Beypazarı'ndaki işletmelerin İstanbul ofis taşımalarında ek mesafe nedeniyle sabah erken hareket planlanmakta; IT altyapısı demonte edilerek özel koruyucu kasalarda iletilmektedir. Kablo düzeni fotoğraflanarak yeniden kurulum kolaylaştırılmaktadır.\n\nBolu güzergâhı sayesinde gün içi teslimat sağlanmaktadır. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak düzenlenmektedir.",
        [("beypazari", ServisTipi.Fuar)]          = "Beypazarı'ndan İstanbul fuar alanlarına taşınan ekipman ve teşhir materyalleri Bolu güzergâhı kullanılarak vibrasyon emici ambalajlarla güvence altına alınmaktadır. Erken rezervasyonla fuar tarihi için araç tahsisi yapılmaktadır.\n\nFuar öncesi zamanında varış sağlanmakta; fuar sonrası geri taşıma için aynı ekip planlanmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("beypazari", ServisTipi.Kamyon)]        = "Beypazarı'ndaki büyük konakların eşya hacmi için 12 ton kapalı kasalı kamyon ile tek seferlik İstanbul taşıması tamamlanmaktadır. Bolu yolunun geniş şeritleri kamyon trafiğine uygun bir güzergâh sunmaktadır.\n\nYükleme sabah erken başlatılarak TEM'e Bolu üzerinden bağlanılmaktadır. İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("beypazari", ServisTipi.Parsiyel)]      = "Beypazarı'ndan İstanbul'a parsiyel araç hizmetinde ek mesafe fiyata yansımakta olup bu durum keşif aşamasında şeffafça bildirilmektedir. Haftalık sefer takviminde Beypazarı'na uygun gün talep bazında belirlenmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir. Toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("beypazari", ServisTipi.Ambar)]         = "Beypazarı'ndaki eşyalar İstanbul'a taşınma tarihine kadar güvenli depomuzda kilitli alanda muhafaza edilmektedir; esnek tarih seçeneğiyle depolama süresi ayarlanabilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.\n\nÇıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",

        // ── KAHRAMANKAZAN ──
        [("kahramankazan", ServisTipi.Kamyonet)]      = "Kahramankazan Merkez ve Yakuplu mahallelerindeki konutlara 3,5 ton kamyonetimiz sabah saatlerinde kolayca ulaşmaktadır; OSB yakınlığındaki adreslerde büyük araç altyapısı da hazır tutulmaktadır. Ekibimiz bölgenin konut ve sanayi adreslerine özgü güzergâh bilgisiyle yükleme koordinasyonunu sorunsuz yürütmektedir.\n\nKahramankazan'dan Sincan aksına geçilerek TEM'e bağlanan araç İstanbul güzergâhına kısa sürede çıkmaktadır. Sabah 06:30 kalkışla aynı gün İstanbul'da kapıdan kapıya teslimat standart olarak tamamlanmaktadır.",
        [("kahramankazan", ServisTipi.Sehirlerarasi)] = "Kahramankazan'dan Sincan aksına geçilerek TEM'e bağlanan güzergâh şehirlerarası taşımaları zaman açısından verimli kılmaktadır. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nSabah 06:30 kalkışla avrupa yakasına öğleden önce, anadolu yakasına öğle saatlerinde ulaşılmaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("kahramankazan", ServisTipi.EvdenEve)]      = "Kazan Merkez'deki konutlarda evden eve taşıma hizmeti sabah erken başlayan yüklemeyle aynı gün İstanbul'da tamamlanmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nSincan–TEM bağlantısı sayesinde aynı gün teslimat standart olarak gerçekleştirilmektedir. Varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("kahramankazan", ServisTipi.Ofis)]          = "Kahramankazan OSB'deki firmalar için İstanbul ofis taşımalarında IT altyapısı güvenli biçimde demonte edilmekte; sunucu, ağ cihazı ve UPS üniteler özel koruyucu kasalarda iletilmektedir. Kablo düzeni fotoğraflanarak İstanbul'daki yeniden kurulum kolaylaştırılmaktadır.\n\nHafta sonu veya gece taşımayla iş sürekliliği korunmakta; kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak sunulmaktadır.",
        [("kahramankazan", ServisTipi.Fuar)]          = "Kahramankazan'daki sanayi firmalarının İstanbul fuar alanlarına taşınan ekipman ve teşhir materyalleri vibrasyon emici ambalajlarla sigortalı olarak nakliyatı yapılmaktadır. Erken rezervasyonla fuar tarihi güvence altına alınmaktadır.\n\nFuar öncesi 2 gün teslimat taahhüdü verilmekte; fuar sonrası geri taşıma için aynı ekip planlanmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("kahramankazan", ServisTipi.Kamyon)]        = "Kahramankazan'daki büyük dairelerden İstanbul'a 12 ton kapalı kasalı kamyon ile tek seferlik taşıma Sincan aksından TEM güzergâhıyla hızla tamamlanmaktadır. Tüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir.\n\nYükleme sabah 06:30'da başlatılmakta; İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("kahramankazan", ServisTipi.Parsiyel)]      = "Kahramankazan'dan İstanbul'a az eşya göndermek için parsiyel araç hizmeti haftalık düzenli sefer ile sunulmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir. Toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("kahramankazan", ServisTipi.Ambar)]         = "Kahramankazan'daki eşyalar güvenli depomuzda kilitli alanda kamera ve nem kontrolü altında İstanbul taşınma tarihine kadar muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",

        // ── ÇUBUK ──
        [("cubuk", ServisTipi.Kamyonet)]      = "Çubuk Merkez ve Ovacık mahallelerinin ara yollarında 3,5 ton kamyonetimiz en güvenli ve uygun ölçekli araç olarak hizmet vermektedir; dar sokak girişlerine manevra kabiliyetiyle sorunsuz erişilmektedir. Yükleme öncesinde adres ve güzergâh değerlendirmesi yapılarak beklenmedik durumlar önlenmektedir.\n\nÇubuk'tan Pursaklar üzerinden Çevre Yolu'na bağlanan araç TEM'e çıkmakta; İstanbul'a aynı gün teslimat sabah erken başlangıçla tamamlanmaktadır. Sabah 06:30 kalkışla öğleden önce İstanbul merkezi ilçelerine ulaşılmaktadır.",
        [("cubuk", ServisTipi.Sehirlerarasi)] = "Çubuk'tan Pursaklar üzerinden Çevre Yolu'na ulaşan şehirlerarası araç TEM'e bağlanarak İstanbul'a aynı gün teslimatı tamamlamaktadır. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nSabah erken başlangıç önerilmekte; avrupa yakasına öğleden önce, anadolu yakasına öğle saatlerinde ulaşılmaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("cubuk", ServisTipi.EvdenEve)]      = "Çubuk'taki evden eve taşımalar için yükleme öncesinde adres ve yol güzergâhı değerlendirmesi yapılmakta; eşya miktarı ve daire büyüklüğüne göre en uygun araç seçilmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmaktadır.\n\nPursaklar–Çevre Yolu bağlantısı sayesinde aynı gün İstanbul teslimatı standart olarak gerçekleştirilmektedir. Varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("cubuk", ServisTipi.Ofis)]          = "Çubuk'taki işletmelerin İstanbul taşımalarında IT ekipmanı güvenli biçimde demonte edilmekte; arşiv için standart koruma uygulanmaktadır. Kablo düzeni fotoğraflanarak yeniden kurulum kolaylaştırılmaktadır.\n\nHafta sonu taşıma seçeneğiyle iş sürekliliği korunmakta; kurumsal fatura ve sigorta belgesi her taşımada standart olarak düzenlenmektedir.",
        [("cubuk", ServisTipi.Fuar)]          = "Çubuk'tan İstanbul fuar taşımalarında önceden tarih planlaması yapılmakta; kalkış saati ve rota fuar takvimi gözetilerek belirlenmektedir. Vibrasyon emici ambalajlarla teşhir materyalleri güvence altına alınmaktadır.\n\nErken rezervasyonla fuar tarihi için araç tahsisi yapılmaktadır. Fuar sonrası geri taşıma için aynı güzergâh ve ekip planlanmaktadır.",
        [("cubuk", ServisTipi.Kamyon)]        = "Çubuk'taki büyük dairelerden İstanbul'a 12 ton kapalı kasalı kamyon ile taşıma için sabah erken başlangıçla Pursaklar aksından Çevre Yolu'na çıkılmaktadır. Tüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir.\n\nİstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("cubuk", ServisTipi.Parsiyel)]      = "Çubuk'tan İstanbul'a az eşya göndermek için parsiyel araç hizmeti rezervasyona dayalı olarak verilmektedir. Ağırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir. Toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("cubuk", ServisTipi.Ambar)]         = "Çubuk'taki eşyalar kısa ya da uzun süreli depolama seçeneğiyle güvenli depomuzda kamera ve nem kontrolü altında tutulmaktadır. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",

        // ── KIZILCAHAMAM ──
        [("kizilcahamam", ServisTipi.Kamyonet)]      = "Kızılcahamam Merkez ve Çeltikçi mahallelerindeki konutlara 3,5 ton kamyonetimiz Çubuk güzergâhından sorunsuz erişmektedir; termal tesis ve tatil köyü çevrelerindeki adresler için güzergâh önceden planlanmaktadır. Yükleme sabah saatlerinde tamamlanarak araç hızla güzergâha çıkmaktadır.\n\nKızılcahamam'dan Bolu–TEM güzergâhı kullanılarak Ankara şehir merkezi tamamen bypass edilmekte; İstanbul'a en hızlı rota üzerinden aynı gün teslimat tamamlanmaktadır. Sabah erken kalkışla öğleden önce İstanbul merkezi ilçelerine ulaşılmaktadır.",
        [("kizilcahamam", ServisTipi.Sehirlerarasi)] = "Kızılcahamam'dan Bolu–TEM güzergâhı kullanılarak İstanbul'a şehirlerarası taşıma Ankara şehir merkezini bypass eden en hızlı rotayı sunmaktadır. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nSabah 06:30 kalkışla araç TEM'e Bolu üzerinden bağlanmakta; İstanbul'a aynı gün teslimat standart olarak tamamlanmaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("kizilcahamam", ServisTipi.EvdenEve)]      = "Kızılcahamam'ın termal bölgesindeki konutlardan ev taşıma planlaması önceden yapılmakta; ağır mobilyalar ve termal tesis döşemesi için özel ekip hazır tutulmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nBolu güzergâhının avantajıyla aynı gün İstanbul teslimatı gerçekleştirilmektedir. Varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("kizilcahamam", ServisTipi.Ofis)]          = "Kızılcahamam'daki termal ve turizm tesislerinden İstanbul ofis veya tesis taşımalarında esnek tarih planlaması yapılmakta; IT ekipmanı güvenli biçimde demonte edilerek iletilmektedir. Kablo düzeni fotoğraflanarak yeniden kurulum kolaylaştırılmaktadır.\n\nBolu güzergâhı sayesinde gün içi teslimat sağlanmaktadır. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak düzenlenmektedir.",
        [("kizilcahamam", ServisTipi.Fuar)]          = "Kızılcahamam'dan İstanbul fuarlarına Bolu güzergâhı üzerinden taşınan ekipman ve teşhir materyalleri vibrasyon emici ambalajlarla güvence altına alınmakta; teslimat tarihinde kesinlik sağlanmaktadır. Erken rezervasyonla araç tahsisi yapılmaktadır.\n\nFuar sonrası geri taşıma için aynı ekip ve güzergâh planlanmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("kizilcahamam", ServisTipi.Kamyon)]        = "Kızılcahamam'daki büyük konutlardan İstanbul'a 12 ton kapalı kasalı kamyon ile taşıma için Bolu yolunun geniş güzergâh avantajından yararlanılmaktadır. Tüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir.\n\nYükleme sabah erken başlatılarak TEM'e Bolu üzerinden bağlanılmaktadır. İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("kizilcahamam", ServisTipi.Parsiyel)]      = "Kızılcahamam'dan İstanbul'a az eşya göndermek için parsiyel araç hizmeti rezervasyon ile verilmektedir. Ağırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir. Toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("kizilcahamam", ServisTipi.Ambar)]         = "Kızılcahamam'daki eşyaların güvenli depolanması ve daha sonra İstanbul'a teslimatı esnek tarihle planlanmaktadır. Eşyalar kamera ve nem kontrolü altındaki kilitli depoda muhafaza edilmektedir.\n\nDepolama süresi haftalık ya da aylık dönemlerde ayarlanabilmektedir. Çıkışta eşyalar İstanbul adresine ekibimizle teslim edilmektedir.",

        // ── NALLIHAN ──
        [("nallihan", ServisTipi.Kamyonet)]      = "Nallıhan Merkez ve Çayırhan mahallelerinden İstanbul'a kamyonet taşıması Bolu güzergâhının coğrafi avantajıyla kısa sürede tamamlanmaktadır. 3,5 ton kamyonetimiz hem merkez sokaklarına hem Çayırhan sanayi adreslerine rahatlıkla erişmektedir.\n\nNallıhan'ın TEM'e olan yakınlığı yükleme tamamlanır tamamlanmaz aracın doğrudan güzergâha çıkmasına imkân tanımaktadır. Sabah 06:30 kalkışla İstanbul'a öğle saatlerinde ulaşılmakta; kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir.",
        [("nallihan", ServisTipi.Sehirlerarasi)] = "Nallıhan'dan TEM'e olan kısa mesafe, şehirlerarası araçların Ankara trafiğine hiç girmeden İstanbul'a ulaşmasını sağlayan nadir bir avantaj sunmaktadır. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nSabah 06:30 kalkışla araç TEM'e hızla bağlanmakta; İstanbul'a aynı gün öğleden sonra teslimat tamamlanmaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("nallihan", ServisTipi.EvdenEve)]      = "Nallıhan'daki evden eve taşımalar için yükleme sabah erken başlatılmakta; TEM'e yakın güzergâh sayesinde öğleden sonra İstanbul'da teslimat yapılmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nTEM bağlantısının avantajıyla aynı gün teslimat standart olarak gerçekleştirilmektedir. Varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("nallihan", ServisTipi.Ofis)]          = "Nallıhan'daki işletmelerin İstanbul taşımalarında IT altyapısı güvenli biçimde demonte edilmekte; kurumsal ekipman güvenliği için standart protokol uygulanmaktadır. Kablo düzeni fotoğraflanarak yeniden kurulum kolaylaştırılmaktadır.\n\nTEM'e yakın konum gün içi teslimatı desteklemektedir. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak düzenlenmektedir.",
        [("nallihan", ServisTipi.Fuar)]          = "Nallıhan'ın TEM'e yakınlığı fuar taşımalarında belirgin zaman avantajı sağlamaktadır; erken rezervasyonla fuar tarihi garantisi verilmektedir. Vibrasyon emici ambalajlarla teşhir materyalleri güvence altına alınmaktadır.\n\nFuar öncesi 2 gün teslimat taahhüdü verilmekte; fuar sonrası geri taşıma için aynı ekip planlanmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("nallihan", ServisTipi.Kamyon)]        = "Nallıhan'daki büyük konutlardan İstanbul'a 12 ton kapalı kasalı kamyon taşıması TEM'e yakın konum sayesinde hızlıca tamamlanmaktadır. Tüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir.\n\nYükleme sabah erken başlatılmakta; İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("nallihan", ServisTipi.Parsiyel)]      = "Nallıhan'dan İstanbul'a az eşya göndermek için parsiyel araç hizmeti haftanın belirlenen günlerinde verilmektedir. Ağırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir. Toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("nallihan", ServisTipi.Ambar)]         = "Nallıhan'daki eşyalar İstanbul'a taşınma gününe kadar güvenli depomuzda kilitli alanda, kamera ve nem kontrolü altında muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",

        // ── AYAŞ ──
        [("ayas", ServisTipi.Kamyonet)]      = "Ayaş Merkez ve Belpınar mahallelerinden İstanbul'a kamyonet taşıması sabah 07:00'de başlatılarak TEM'e Sincan aksından çıkılmaktadır. 3,5 ton kamyonetimiz ilçe içi dar yollarda ve köy mahallelerinde sorunsuz manevra yapmaktadır.\n\nSincan üzerinden TEM'e bağlanan güzergâh Ankara şehir merkezini bypass etmekte; İstanbul'a aynı gün öğleden sonra teslimat tamamlanmaktadır. Kapıdan kapıya hizmet standart olarak uygulanmaktadır.",
        [("ayas", ServisTipi.Sehirlerarasi)] = "Ayaş'tan Sincan üzerinden TEM'e bağlanan güzergâh şehirlerarası araçların aynı gün İstanbul'a ulaşmasını sağlamaktadır. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nSabah 07:00 kalkışla araç TEM'e Sincan aksından bağlanmakta; İstanbul'a aynı gün teslimat tamamlanmaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("ayas", ServisTipi.EvdenEve)]      = "Ayaş'taki evden eve taşımalar için eşya hacmi ve daire büyüklüğüne göre araç seçimi yapılmakta; kapıdan kapıya hizmet sunulmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nSincan–TEM güzergâhıyla aynı gün İstanbul teslimatı gerçekleştirilmektedir. Varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("ayas", ServisTipi.Ofis)]          = "Ayaş'taki işletmelerin İstanbul taşımalarında IT ekipmanı ve arşiv için kurumsal paket uygulanmakta; demonte edilen altyapı özel koruyucu kasalarda iletilmektedir. Kablo düzeni fotoğraflanarak yeniden kurulum kolaylaştırılmaktadır.\n\nHafta sonu taşıma seçeneğiyle iş sürekliliği korunmakta; kurumsal fatura ve sigorta belgesi her taşımada standart olarak düzenlenmektedir.",
        [("ayas", ServisTipi.Fuar)]          = "Ayaş'tan İstanbul fuar taşımalarında zamanında teslimat için sabah erken başlangıç planlanmakta; vibrasyon emici ambalajlarla teşhir materyalleri güvence altına alınmaktadır. Erken rezervasyonla araç tahsisi yapılmaktadır.\n\nFuar sonrası geri taşıma için aynı güzergâh ve ekip planlanmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("ayas", ServisTipi.Kamyon)]        = "Ayaş'taki büyük dairelerden İstanbul'a 12 ton kapalı kasalı kamyon ile tek seferlik taşıma Sincan aksından TEM güzergâhı üzerinden tamamlanmaktadır. Tüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir.\n\nYükleme sabah 07:00'de başlatılmakta; İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("ayas", ServisTipi.Parsiyel)]      = "Ayaş'tan İstanbul'a az eşya göndermek için parsiyel araç hizmeti talebe göre rezervasyonla verilmektedir. Ağırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir. Toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("ayas", ServisTipi.Ambar)]         = "Ayaş'taki eşyalar depolama hizmetiyle güvenli depomuzda bekletilmekte; İstanbul'a taşınma gününde ekibimizle teslim edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nDepo tesisi kamera ve nem kontrol sistemiyle donatılmıştır. Çıkışta taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",

        // ── BALA ──
        [("bala", ServisTipi.Kamyonet)]      = "Bala Merkez ve Hacılar mahallelerinden İstanbul'a kamyonet taşıması Ankara güneydoğu Çevre Yolu'ndan TEM'e erişimle sabah erken başlatılmaktadır. 3,5 ton kamyonetimiz ilçe içi ara yollarda sorunsuz manevra yaparken eşya hacmi önceden değerlendirilerek uygun kapasite seçilmektedir.\n\nÇevre Yolu'na kısa sürede çıkılan güzergâh sayesinde İstanbul'a aynı gün teslimat tamamlanmaktadır. Sabah 06:30 kalkışla kapıdan kapıya hizmet standart olarak uygulanmaktadır.",
        [("bala", ServisTipi.Sehirlerarasi)] = "Bala'nın Ankara güneydoğu Çevre Yolu güzergâhı üzerinden TEM'e bağlanması şehirlerarası taşımada aynı gün teslimata imkân tanımaktadır. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nSabah erken kalkışla araç Çevre Yolu'ndan TEM'e çıkmakta; İstanbul'a aynı gün öğleden sonra teslimat tamamlanmaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("bala", ServisTipi.EvdenEve)]      = "Bala'daki evden eve taşımalar için daire keşfi ve eşya miktarı önceden değerlendirilerek araç kapasitesi belirlenmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nÇevre Yolu–TEM güzergâhıyla aynı gün İstanbul teslimatı gerçekleştirilmektedir. Varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("bala", ServisTipi.Ofis)]          = "Bala'daki küçük işletmelerin İstanbul ofis taşımalarında IT ve arşiv için standart kurumsal protokol uygulanmakta; ekipman özel koruyucu kasalarda iletilmektedir. Kablo düzeni fotoğraflanarak yeniden kurulum kolaylaştırılmaktadır.\n\nÇevre Yolu güzergâhı sayesinde gün içi teslimat sağlanmaktadır. Kurumsal fatura ve sigorta belgesi her taşımada standart olarak düzenlenmektedir.",
        [("bala", ServisTipi.Fuar)]          = "Bala'dan İstanbul fuar taşımalarında ek mesafe gözetilerek sabah erken kalkış planlanmakta; vibrasyon emici ambalajlarla teşhir materyalleri güvence altına alınmaktadır. Erken rezervasyonla araç tahsisi yapılmaktadır.\n\nZamanında teslimat taahhüdü verilmekte; fuar sonrası geri taşıma için aynı güzergâh ve ekip planlanmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("bala", ServisTipi.Kamyon)]        = "Bala'daki büyük konutlardan İstanbul'a 12 ton kapalı kasalı kamyon ile tek seferlik taşıma güneydoğu Çevre Yolu'ndan TEM'e bağlanarak tamamlanmaktadır. Tüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir.\n\nYükleme sabah erken başlatılmakta; İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("bala", ServisTipi.Parsiyel)]      = "Bala'dan İstanbul'a az eşya göndermek için parsiyel araç hizmeti mesafe farkı gözetilerek fiyatlandırılmakta; bu durum keşif aşamasında şeffafça bildirilmektedir. Haftalık sefer takviminde Bala'ya uygun gün talep bazında belirlenmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir. Toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("bala", ServisTipi.Ambar)]         = "Bala'daki eşyalar İstanbul'a taşınma tarihine kadar güvenli depomuzda kilitli alanda muhafaza edilmektedir; esnek tarihli depolama hizmetiyle plan kolaylıkla ayarlanabilmektedir. Depo tesisi kamera ve nem kontrol sistemiyle donatılmıştır.\n\nÇıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",

        // ── GÜDÜL ──
        [("gudul", ServisTipi.Kamyonet)]      = "Güdül Merkez ve Kabaklar mahallelerine erişen 3,5 ton kamyonetimiz dar ve virajlı yollarda güvenle manevra yapabilmektedir; büyük araçların giremeyeceği mahalle içi adreslere standart çözüm kamyonettir. Yükleme öncesinde adres ve güzergâh değerlendirmesi yapılmaktadır.\n\nGüdül'den Beypazarı aksından Bolu–TEM güzergâhına bağlanan rota Ankara şehir merkezini bypass ederek İstanbul'a hızlı erişim sağlamaktadır. Sabah erken kalkışla aynı gün teslimat tamamlanmaktadır.",
        [("gudul", ServisTipi.Sehirlerarasi)] = "Güdül'den Beypazarı aksından Bolu–TEM güzergâhına bağlanan rota Ankara şehir merkezini bypass ederek İstanbul'a hızlı şehirlerarası erişim sağlamaktadır. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nSabah erken kalkışla araç TEM'e Bolu üzerinden bağlanmakta; İstanbul'a aynı gün teslimat tamamlanmaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("gudul", ServisTipi.EvdenEve)]      = "Güdül'deki evden eve taşımalar için araç erişimi ve yol ölçüleri önceden değerlendirilmekte; dar yollu adresler için kamyonet standart çözüm olmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nBeypazarı–Bolu güzergâhı sayesinde aynı gün İstanbul teslimatı gerçekleştirilmektedir. Varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("gudul", ServisTipi.Ofis)]          = "Güdül'deki küçük ölçekli işletmelerin İstanbul taşımalarında IT ekipmanı koruması için standart kurumsal paket sunulmakta; demonte edilen ekipman özel kasalarda iletilmektedir. Kablo düzeni fotoğraflanarak yeniden kurulum kolaylaştırılmaktadır.\n\nBolu güzergâhı sayesinde gün içi teslimat sağlanmaktadır. Kurumsal fatura ve sigorta belgesi her taşımada standart olarak düzenlenmektedir.",
        [("gudul", ServisTipi.Fuar)]          = "Güdül'den İstanbul fuar taşımalarında güzergâh ve zaman planlaması önceden titizlikle yapılmakta; zamanında teslimat garantisi verilmektedir. Vibrasyon emici ambalajlarla teşhir materyalleri güvence altına alınmaktadır.\n\nErken rezervasyonla araç tahsisi yapılmaktadır. Fuar sonrası geri taşıma için aynı güzergâh ve ekip planlanmaktadır.",
        [("gudul", ServisTipi.Kamyon)]        = "Güdül'deki büyük konutlardan İstanbul'a kamyon taşıması için araç erişimi önceden değerlendirilmekte; gerekirse kamyonet ile ön transfer sonrası şehirlerarası araç devreye alınmaktadır. Tüm eşyalar envanter listesiyle belgelenmektedir.\n\nBeypazarı–Bolu güzergâhı üzerinden TEM'e bağlanılmakta; İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("gudul", ServisTipi.Parsiyel)]      = "Güdül'den İstanbul'a az eşya göndermek için parsiyel araç hizmeti talebe dayalı olarak planlanmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir. Toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("gudul", ServisTipi.Ambar)]         = "Güdül'deki eşyalar kısa ya da uzun süreli depolama seçeneğiyle güvenli depomuzda kamera ve nem kontrolü altında tutulmaktadır. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",

        // ── ÇAMLIDERE ──
        [("camlidere", ServisTipi.Kamyonet)]      = "Çamlıdere Merkez ve Çamkoru mahallelerine erişen 3,5 ton kamyonetimiz ormanlık alanlardaki dar ve kıvrımlı yollarda güvenle çalışmaktadır; büyük araçların ulaşamadığı köy içi adreslere standart çözüm kamyonettir. Yükleme öncesinde güzergâh ve adres erişimi önceden değerlendirilmektedir.\n\nÇamlıdere'den Kızılcahamam–Bolu yolu üzerinden TEM'e bağlanan güzergâh Ankara şehir merkezini tamamen atlayarak İstanbul'a ulaşmaktadır. Sabah erken kalkışla aynı gün teslimat tamamlanmaktadır.",
        [("camlidere", ServisTipi.Sehirlerarasi)] = "Çamlıdere'den Kızılcahamam–Bolu yolu üzerinden TEM'e bağlanan güzergâh Ankara şehir merkezini tamamen atlayarak İstanbul'a şehirlerarası taşımada doğrudan erişim sağlamaktadır. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nSabah erken kalkışla araç TEM'e Bolu üzerinden bağlanmakta; İstanbul'a aynı gün teslimat tamamlanmaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("camlidere", ServisTipi.EvdenEve)]      = "Çamlıdere'nin sınırlı erişim yolları nedeniyle ev taşıma planlaması araç erişim değerlendirmesiyle başlatılmakta; dar yollar için kamyonet standart çözüm olmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nKızılcahamam–Bolu güzergâhıyla aynı gün İstanbul teslimatı gerçekleştirilmektedir. Varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("camlidere", ServisTipi.Ofis)]          = "Çamlıdere'deki işletmelerin İstanbul taşımalarında ek mesafe gözetilerek esnek tarih planlaması yapılmakta; IT ekipmanı güvenli biçimde demonte edilerek iletilmektedir. Kablo düzeni fotoğraflanarak yeniden kurulum kolaylaştırılmaktadır.\n\nBolu güzergâhı sayesinde gün içi teslimat sağlanmaktadır. Kurumsal fatura ve sigorta belgesi her taşımada standart olarak düzenlenmektedir.",
        [("camlidere", ServisTipi.Fuar)]          = "Çamlıdere'den İstanbul fuar taşımalarında Bolu güzergâhı kullanılarak taşıma süresi optimize edilmekte; vibrasyon emici ambalajlarla teşhir materyalleri güvence altına alınmaktadır. Erken rezervasyonla araç tahsisi yapılmaktadır.\n\nZamanında teslimat taahhüdü verilmekte; fuar sonrası geri taşıma için aynı güzergâh ve ekip planlanmaktadır.",
        [("camlidere", ServisTipi.Kamyon)]        = "Çamlıdere'deki büyük konutlardan İstanbul'a kamyon taşımalarında gerekirse ilçe girişinde kamyonet ile ön transfer sonrası şehirlerarası araç devreye alınmaktadır. Tüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir.\n\nKızılcahamam–Bolu–TEM güzergâhıyla İstanbul'a aynı gün teslimat tamamlanmaktadır. İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("camlidere", ServisTipi.Parsiyel)]      = "Çamlıdere'den İstanbul'a parsiyel araç hizmeti talep bazlı olarak planlanmakta; ek mesafe fiyata yansımakta ve bu durum keşif aşamasında şeffafça bildirilmektedir. Ağırlık ve hacme göre fiyatlandırma yapılmaktadır.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir. Toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("camlidere", ServisTipi.Ambar)]         = "Çamlıdere'deki eşyalar İstanbul'a taşınma tarihine kadar güvenli depomuzda kamera ve nem kontrolü altında kilitli alanda muhafaza edilmektedir. Esnek tarihli depolama seçeneğiyle plan kolaylıkla ayarlanabilmektedir.\n\nÇıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",

        // ── HAYMANA ──
        [("haymana", ServisTipi.Kamyonet)]      = "Haymana Merkez ve Yeşilyurt mahallelerinden İstanbul'a kamyonet taşıması Çankaya aksından Ankara güneybatı Çevre Yolu'na bağlanarak sabah erken başlatılmaktadır. 3,5 ton kamyonetimiz ilçe içi ara yollarda sorunsuz manevra yaparken eşya miktarı önceden değerlendirilerek uygun kapasite seçilmektedir.\n\nÇevre Yolu'na kısa sürede çıkılan güzergâh sayesinde İstanbul'a aynı gün teslimat tamamlanmaktadır. Sabah 06:30 kalkışla kapıdan kapıya hizmet standart olarak uygulanmaktadır.",
        [("haymana", ServisTipi.Sehirlerarasi)] = "Haymana'dan Ankara Çevre Yolu üzerinden TEM'e ulaşan şehirlerarası araç İstanbul'a aynı gün teslimatı tamamlamaktadır. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nHaymana'nın güneybatı konumuna karşın sabah erken kalkışla Çevre Yolu–TEM güzergâhı aynı gün teslimatı mümkün kılmaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("haymana", ServisTipi.EvdenEve)]      = "Haymana'nın güneybatı konumuna karşın evden eve taşıma planlaması erken başlangıçla aynı gün teslimatı mümkün kılmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nÇevre Yolu–TEM güzergâhıyla aynı gün İstanbul teslimatı gerçekleştirilmektedir. Varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("haymana", ServisTipi.Ofis)]          = "Haymana'daki işletmelerin İstanbul ofis taşımalarında IT ekipmanı güvenli biçimde demonte edilmekte; arşiv güvenliği için standart kurumsal protokol uygulanmaktadır. Kablo düzeni fotoğraflanarak yeniden kurulum kolaylaştırılmaktadır.\n\nÇevre Yolu güzergâhı sayesinde gün içi teslimat sağlanmaktadır. Kurumsal fatura ve sigorta belgesi her taşımada standart olarak düzenlenmektedir.",
        [("haymana", ServisTipi.Fuar)]          = "Haymana'dan İstanbul fuar taşımalarında ek mesafe gözetilerek sabah erken başlangıç planlanmakta; vibrasyon emici ambalajlarla teşhir materyalleri güvence altına alınmaktadır. Erken rezervasyonla araç tahsisi yapılmaktadır.\n\nZamanında teslimat taahhüdü verilmekte; fuar sonrası geri taşıma için aynı güzergâh ve ekip planlanmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("haymana", ServisTipi.Kamyon)]        = "Haymana'daki büyük konutlardan İstanbul'a 12 ton kapalı kasalı kamyon erken başlangıçla Çevre Yolu–TEM güzergâhı üzerinden aynı gün teslimata ulaşmaktadır. Tüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir.\n\nYükleme sabah 06:30'da başlatılmakta; İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("haymana", ServisTipi.Parsiyel)]      = "Haymana'dan İstanbul'a az eşya göndermek için parsiyel araç hizmeti talep bazlı olarak verilmektedir. Ağırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir. Toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("haymana", ServisTipi.Ambar)]         = "Haymana'daki eşyalar İstanbul'a taşınma gününe kadar güvenli depomuzda kilitli alanda kamera ve nem kontrolü altında muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",

        // ── EVREN ──
        [("evren", ServisTipi.Kamyonet)]      = "Evren Merkez ve Boyalı mahallelerinin dar ve engebeli yollarında 3,5 ton kamyonetimiz tek uygun araç seçeneğini oluşturmaktadır; büyük araçlar ilçe girişinde bekleme yaparak ikincil kamyonetle koordineli çalışmaktadır. Yükleme öncesinde adres ve yol güzergâhı özellikle değerlendirilerek beklenmedik engeller önlenmektedir.\n\nEvren'den Kırıkkale aksından Ankara Çevre Yolu'na çıkış sağlanmakta; araç TEM'e bağlanarak İstanbul'a aynı gün teslimatı tamamlamaktadır. Sabah 06:30 kalkışla kapıdan kapıya hizmet standart olarak uygulanmaktadır.",
        [("evren", ServisTipi.Sehirlerarasi)] = "Evren'den İstanbul'a şehirlerarası taşımada Kırıkkale aksından Ankara Çevre Yolu'na bağlantı için ön koordinasyon gerekmekte; sabah 06:30'da başlayan yüklemeyle araç İstanbul güzergâhına vakit kaybetmeden çıkmaktadır. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nKamyonet ile tamamlanan yükleme sonrasında şehirlerarası araç devreye girmekte; İstanbul'a aynı gün kapıdan kapıya teslimat standart olarak gerçekleştirilmektedir. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("evren", ServisTipi.EvdenEve)]      = "Evren'deki evden eve taşımalar için önce kamyonetle eşyalar toplanmakta; ilçe girişindeki şehirlerarası araçla aktarım yapılarak İstanbul'a kapıdan kapıya teslimat tamamlanmaktadır. Araç erişim planlaması ve ikincil araç koordinasyonu yükleme günü öncesinde ekibimizce ayrıntılı biçimde hazırlanmaktadır.\n\nHer eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır. İstanbul'daki yeni konuta varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("evren", ServisTipi.Ofis)]          = "Evren'deki küçük ölçekli işletmelerin İstanbul ofis taşımalarında ek mesafe nedeniyle sabah erken hareket planlanmakta; IT ekipmanı güvenli biçimde demonte edilerek özel koruyucu kasalarda iletilmektedir. İkincil araç koordinasyonuyla tüm ekipman güvenle nakledilmektedir.\n\nKablo düzeni fotoğraflanarak İstanbul'daki yeniden kurulum kolaylaştırılmaktadır. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak düzenlenmektedir.",
        [("evren", ServisTipi.Fuar)]          = "Evren'den İstanbul fuar alanlarına taşınan stand sistemleri ve teşhir materyalleri vibrasyon emici ambalajlarla güvence altına alınmakta; uzak konumu nedeniyle fuar tarihinden en az 3 gün öncesinden yükleme planlanmaktadır. Güzergâh ve zaman planlaması önceden titizlikle yapılarak zamanında teslimat garantisi verilmektedir.\n\nFuar sonrası geri taşıma için aynı güzergâh ve ekip planlanmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("evren", ServisTipi.Kamyon)]        = "Evren'den İstanbul'a büyük daire taşımalarında kamyon ilçe girişinde beklemekte; kamyonetle tamamlanan iç transfer sonrası eşyalar şehirlerarası araca aktarılarak tek seferlik teslimat tamamlanmaktadır. Tüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir.\n\nSabah erken başlayan yüklemeyle Ankara Çevre Yolu–TEM güzergâhından İstanbul'a aynı gün teslimat sağlanmaktadır. İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("evren", ServisTipi.Parsiyel)]      = "Evren'den İstanbul'a az eşya veya birkaç parça mobilya göndermek için parsiyel araç hizmeti talebe göre koordineli biçimde planlanmaktadır. İlçe içi toplamanın ardından şehirlerarası araca aktarım gerçekleştirilerek İstanbul'a ekonomik teslimat sağlanmaktadır.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü önceden bildirilmektedir. Kırılgan parçalar için ek ambalaj seçeneği geçerlidir.",
        [("evren", ServisTipi.Ambar)]         = "Evren'deki eşyaların depolanması ve İstanbul'a taşınma gününde koordineli teslimi için güvenli depolama hizmeti sunulmaktadır; eşyalar kamera ve nem kontrolü altındaki kilitli depomuzda muhafaza edilmektedir. Depolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir.\n\nÇıkışta eşyalar İstanbul adresine ikincil araç koordinasyonu dahil ekibimizce teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",

        // ── KALECİK ──
        [("kalecik", ServisTipi.Kamyonet)]      = "Kalecik Merkez ve Erikli mahallelerinin vadideki dar yolları ile tarihi kale çevresinin kıvrımlı sokaklarında 3,5 ton kamyonetimiz en uygun araç seçeneğini oluşturmaktadır; büyük araçların ulaşamadığı mahalle içi adreslere standart çözüm kamyonettir. Yükleme öncesinde adres ve güzergâh değerlendirmesi yapılarak en kısa yol belirlenmektedir.\n\nKalecik'ten Akyurt aksından kuzey Çevre Yolu'na ulaşan araç TEM'e bağlanarak İstanbul'a hızla yola çıkmaktadır. Sabah 06:30 kalkışla öğleden önce İstanbul merkezi ilçelerine ulaşılmakta; kapıdan kapıya hizmet standart olarak uygulanmaktadır.",
        [("kalecik", ServisTipi.Sehirlerarasi)] = "Kalecik'ten Akyurt aksından kuzey Çevre Yolu'na ulaşan şehirlerarası araç TEM'e bağlanarak İstanbul'a aynı gün teslimatı tamamlamaktadır. Tüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir.\n\nSabah 06:30 kalkışla avrupa yakasına öğleden önce, anadolu yakasına öğle saatlerinde ulaşılmaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("kalecik", ServisTipi.EvdenEve)]      = "Kalecik'teki evden eve taşımalar için araç erişimi ve güzergâh önceden belirlenmekte; dar kale sokakları için kamyonet boyutu taşıma güvenliğini garanti etmektedir. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nAkyurt–Çevre Yolu–TEM güzergâhıyla aynı gün İstanbul teslimatı kapıdan kapıya standart olarak gerçekleştirilmektedir. Varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("kalecik", ServisTipi.Ofis)]          = "Kalecik'teki işletmelerin İstanbul taşımalarında IT ekipmanı güvenli biçimde demonte edilerek özel koruyucu kasalarda iletilmekte; arşiv kutuları kilitli kolilerde taşınmaktadır. Kablo düzeni fotoğraflanarak İstanbul'daki yeniden kurulum kolaylaştırılmaktadır.\n\nHafta sonu veya gece taşıma seçeneğiyle iş sürekliliği korunmakta; kurumsal fatura ve sigorta belgesi her taşımada standart olarak düzenlenmektedir.",
        [("kalecik", ServisTipi.Fuar)]          = "Kalecik'ten İstanbul fuar alanlarına taşınan stand ve teşhir materyalleri vibrasyon emici ambalajlarla güvence altına alınmakta; güzergâh ve tarih planlaması önceden yapılarak zamanında teslimat garantisi verilmektedir. Erken rezervasyonla fuar tarihi için araç tahsisi yapılmaktadır.\n\nFuar sonrası geri taşıma için aynı güzergâh ve ekip planlanmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("kalecik", ServisTipi.Kamyon)]        = "Kalecik'teki büyük konutlardan İstanbul'a 12 ton kapalı kasalı kamyon taşıması için araç erişim planlaması titizlikle yapılmakta; dar yollarda gerekirse kamyonet ikincil transferiyle eşyalar şehirlerarası araca aktarılmaktadır. Tüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir.\n\nYükleme sabah erken başlatılarak Akyurt aksından TEM'e bağlanılmaktadır. İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("kalecik", ServisTipi.Parsiyel)]      = "Kalecik'ten İstanbul'a az eşya göndermek için parsiyel araç hizmeti talep bazlı olarak haftanın belirlenen günleri planlanmaktadır. Ağırlık ve hacme göre fiyatlandırma yapılmakta; kalkış günü önceden bildirilmektedir.\n\nKırılgan parçalar için ek ambalaj seçeneği geçerlidir. Toplama adresinden İstanbul teslim noktasına 1–2 iş günü süre öngörülmektedir.",
        [("kalecik", ServisTipi.Ambar)]         = "Kalecik'teki eşyaların güvenli depolanması ve İstanbul'a zamanında teslimi için esnek tarihli depolama hizmeti sunulmaktadır. Eşyalar kamera ve nem kontrolü altındaki kilitli depomuzda muhafaza edilmektedir.\n\nDepolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir. Çıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",

        // ── ŞEREFLİKOÇHİSAR ──
        [("sereflikocehisar", ServisTipi.Kamyonet)]      = "Şereflikoçhisar Merkez ve Akpınar mahallelerinden İstanbul'a kamyonet taşıması yaklaşık 560 km güzergâh nedeniyle sabah 06:00–07:00 gibi erken başlatılmaktadır; ek mesafe maliyeti keşif aşamasında şeffafça müşteriyle paylaşılmaktadır. 3,5 ton kamyonetimiz ilçe içi geniş bulvarlara ve dar ara sokaklara eşit kolaylıkla erişmektedir.\n\nŞereflikoçhisar'dan Ankara Çevre Yolu'na çıkışla TEM'e bağlanan araç İstanbul'a aynı gün öğleden sonra teslimatı tamamlamaktadır. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("sereflikocehisar", ServisTipi.Sehirlerarasi)] = "Şereflikoçhisar'dan İstanbul'a yaklaşık 560 km şehirlerarası taşımada araç sabah 06:00 gibi erken kalkış yaparak Ankara Çevre Yolu–TEM güzergâhından aynı gün teslimatı tamamlamaktadır. Ek mesafe maliyeti Ankara merkez ilçelerine kıyasla %20–30 fazla yansıyabilir; bu durum keşif aşamasında şeffafça bildirilmektedir.\n\nTüm eşyalar nakliye sigortası kapsamına alınmakta ve envanter listesiyle belgelenmektedir. Kapıdan kapıya hizmet İstanbul'un her ilçesine standart olarak geçerlidir.",
        [("sereflikocehisar", ServisTipi.EvdenEve)]      = "Şereflikoçhisar'ın uzak konumu gözetilerek evden eve taşıma planlaması sabah 06:00 başlangıcıyla aynı gün teslimat hedefiyle hazırlanmaktadır. Her eşya balonlu naylon ve battaniye ambalajıyla korunmakta; taşıma öncesinde envanter fotoğraflaması yapılmaktadır.\n\nÇevre Yolu–TEM güzergâhıyla İstanbul'a kapıdan kapıya teslimat gerçekleştirilmektedir. Varışta mobilyalar monte edilmekte ve eşyalar odaya yerleştirilmektedir.",
        [("sereflikocehisar", ServisTipi.Ofis)]          = "Şereflikoçhisar'daki tuz ve tarım sektörü firmalarının İstanbul ofis taşımalarında IT ekipmanı güvenli biçimde demonte edilmekte; arşiv için kilitli koliler ve standart koruma uygulanmaktadır. Ek mesafe nedeniyle sabah 06:00'da başlayan yüklemeyle gün içi teslimat sağlanmaktadır.\n\nKablo düzeni fotoğraflanarak İstanbul'daki yeniden kurulum kolaylaştırılmaktadır. Kurumsal fatura, sigorta belgesi ve envanter listesi her taşımada standart olarak düzenlenmektedir.",
        [("sereflikocehisar", ServisTipi.Fuar)]          = "Şereflikoçhisar'dan İstanbul fuar alanlarına uzak mesafe taşımacılığı için fuar tarihinden minimum 3 gün öncesinden rezervasyon alınmakta; araç ve güzergâh planlaması titizlikle yapılmaktadır. Teşhir materyalleri ve stand bileşenleri vibrasyon emici ambalajlarla güvence altına alınmaktadır.\n\nZamanında teslimat garantisi verilmekte; fuar sonrası geri taşıma için aynı ekip planlanmaktadır. Hasar durumunda sigorta kapsamında tutanak tutulmaktadır.",
        [("sereflikocehisar", ServisTipi.Kamyon)]        = "Şereflikoçhisar'daki büyük konutlardan İstanbul'a 12 ton kapalı kasalı kamyon taşıması ek mesafe nedeniyle sabah 06:00'da başlamakta; Ankara Çevre Yolu–TEM güzergâhından geçerek aynı gün teslimata ulaşılmaktadır. Tüm eşyalar envanter listesiyle belgelenmekte ve nakliye sigortasına dahil edilmektedir.\n\nBüyük araç kapasitesi ile tüm mobilya ve eşyalar tek seferde taşınmaktadır. İstanbul'da teslimatta büyük mobilyalar odaya taşınmakta ve monte edilmektedir.",
        [("sereflikocehisar", ServisTipi.Parsiyel)]      = "Şereflikoçhisar'dan İstanbul'a parsiyel araç hizmetinde uzak mesafe ek ücreti fiyata yansımakta; bu durum keşif aşamasında şeffafça bildirilmektedir. İleri tarihli rezervasyon yapılarak haftalık sefer takvimine dahil edilmektedir.\n\nAğırlık ve hacme göre fiyatlandırma yapılmakta; kırılgan parçalar için ek ambalaj seçeneği geçerlidir. Toplama adresinden İstanbul teslim noktasına 2–3 iş günü süre öngörülmektedir.",
        [("sereflikocehisar", ServisTipi.Ambar)]         = "Şereflikoçhisar'daki eşyaların depolanması İstanbul'a taşınma tarihine kadar güvenli muhafaza için ideal çözümdür; uzak konumu gözetilerek erken depolama planlaması önerilmektedir. Eşyalar kamera ve nem kontrolü altındaki kilitli depomuzda muhafaza edilmektedir.\n\nDepolama süresi haftalık ya da aylık dönemlerde esnek planlanabilmektedir. Çıkışta eşyalar İstanbul adresine ekibimizle teslim edilmekte; taşıma ücreti o tarihin tarife fiyatına göre bildirilmektedir.",
    };
}
